// Virtualized <tbody> for large data tables: only mounts row TRs near the scroll viewport.
import React, { useCallback, useLayoutEffect, useRef, useState } from 'react';

const DEFAULT_ROW_HEIGHT = 56;
const DEFAULT_MAX_HEIGHT = '72vh';
/** Rows to render above/below the viewport (total extra ≈ 2 * overscan). */
const DEFAULT_OVERSCAN = 40;

function useVirtualWindow({
  rowCount,
  rowHeight,
  scrollRef,
  overscan = DEFAULT_OVERSCAN,
}) {
  const [win, setWin] = useState(() => {
    if (rowCount === 0) return { start: 0, end: 0, padTop: 0, padBottom: 0 };
    const end = Math.min(rowCount, overscan + 28);
    return {
      start: 0,
      end,
      padTop: 0,
      padBottom: (rowCount - end) * rowHeight,
    };
  });

  const update = useCallback(() => {
    const el = scrollRef.current;
    if (!el || rowCount === 0) {
      setWin({ start: 0, end: 0, padTop: 0, padBottom: 0 });
      return;
    }
    const { scrollTop, clientHeight } = el;
    const start = Math.max(0, Math.floor(scrollTop / rowHeight) - overscan);
    const end = Math.min(
      rowCount,
      Math.ceil((scrollTop + clientHeight) / rowHeight) + overscan,
    );
    setWin({
      start,
      end,
      padTop: start * rowHeight,
      padBottom: (rowCount - end) * rowHeight,
    });
  }, [rowCount, rowHeight, overscan, scrollRef]);

  useLayoutEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    let frame = 0;
    const schedule = () => {
      if (frame) cancelAnimationFrame(frame);
      frame = requestAnimationFrame(() => {
        frame = 0;
        update();
      });
    };
    schedule();
    el.addEventListener('scroll', schedule, { passive: true });
    const ro = new ResizeObserver(schedule);
    ro.observe(el);
    return () => {
      if (frame) cancelAnimationFrame(frame);
      el.removeEventListener('scroll', schedule);
      ro.disconnect();
    };
  }, [update, scrollRef]);

  return { ...win, update };
}

function SpacerRow({ colSpan, height }) {
  if (height <= 0) return null;
  return (
    <tr aria-hidden="true" className="virtual-spacer">
      <td
        colSpan={colSpan}
        style={{
          height,
          padding: 0,
          border: 0,
          verticalAlign: 'top',
          lineHeight: 0,
          fontSize: 0,
        }}
      />
    </tr>
  );
}

/**
 * @param {object} props
 * @param {React.ReactNode} props.head — <thead>…</thead>
 * @param {number} props.colSpan — column count for spacer cells
 * @param {any[]} props.rows
 * @param {(row: any, index: number) => React.ReactNode} props.renderRow — return <tr>…</tr>
 * @param {number} [props.rowHeight]
 * @param {string} [props.maxHeight] — CSS max-height of the scroll area
 * @param {number} [props.overscan]
 * @param {any} [props.resetScrollDeps] — when this value changes, scrollTop resets to 0
 */
export function VirtualScrollTable({
  head,
  colSpan,
  rows,
  renderRow,
  rowHeight = DEFAULT_ROW_HEIGHT,
  maxHeight = DEFAULT_MAX_HEIGHT,
  overscan = DEFAULT_OVERSCAN,
  resetScrollDeps = null,
}) {
  const scrollRef = useRef(null);
  const { start, end, padTop, padBottom, update } = useVirtualWindow({
    rowCount: rows.length,
    rowHeight,
    scrollRef,
    overscan,
  });

  useLayoutEffect(() => {
    const el = scrollRef.current;
    if (el) el.scrollTop = 0;
    update();
  }, [resetScrollDeps, update]);

  const slice = rows.slice(start, end);

  return (
    <div
      ref={scrollRef}
      className="virtual-table-scroll"
      style={{
        maxHeight,
        overflow: 'auto',
        position: 'relative',
      }}
    >
      <table className="dt virtual-dt">
        {head}
        <tbody>
          <SpacerRow colSpan={colSpan} height={padTop} />
          {slice.map((row, i) => renderRow(row, start + i))}
          <SpacerRow colSpan={colSpan} height={padBottom} />
        </tbody>
      </table>
    </div>
  );
}
