// Overview screen — hero KPIs, headline charts, NZ map
import React, { useMemo, useState } from 'react';
import { Chart } from './charts.jsx';
import { fmt } from './utils.js';
import { ABM } from './data.js';

function sumSubcontractors(p) {
  return p.subcontractors.reduce((q, sc) => q + sc.allocated, 0);
}

const SEG_SUB_COLOR = 'color-mix(in srgb, var(--accent) 45%, var(--ink-3))';

export function Overview({ run, year, regionFilter, setRegionFilter, showUnassigned, onOpenProject }) {
  const cur = run[year];
  if (!cur) return null;
  const s = cur.stats;
  const fm = fmt;
  const [metricMode, setMetricMode] = useState('deficit');

  const years = Object.keys(run).map(Number).sort((a,b)=>a-b);
  const trend = years.map(y => ({
    year: y,
    unassigned: run[y].stats.projects_unassigned,
    fully: run[y].stats.projects_fully_allocated,
    partial: run[y].stats.projects_partially_allocated,
    allocPct: run[y].stats.total_paw > 0
      ? run[y].stats.total_value_allocated / run[y].stats.total_paw : 0,
  }));

  const filteredProjects = regionFilter
    ? cur.projects.filter(p => p.region === regionFilter)
    : cur.projects;

  const filteredCompanies = useMemo(() =>
    (regionFilter
      ? cur.companies.filter(c => c.region === regionFilter)
      : cur.companies),
  [cur.companies, regionFilter]);

  const rb = regionFilter ? s.per_region_breakdown?.[regionFilter] : null;
  const fUnassigned = regionFilter
    ? (rb?.unassigned ?? filteredProjects.filter(p => p.main_contractor_id == null).length)
    : s.projects_unassigned;
  const fTotal = regionFilter
    ? (rb?.total ?? filteredProjects.length)
    : s.total_projects;
  const fAllocPct = regionFilter
    ? (() => {
        if (rb && rb.total > 0) return (rb.total - rb.unassigned) / rb.total;
        const totalPaw = filteredProjects.reduce((a, p) => a + p.paw, 0);
        const alloc = filteredProjects.reduce((a, p) => a + p.main_allocated + sumSubcontractors(p), 0);
        return totalPaw > 0 ? alloc / totalPaw : 0;
      })()
    : (s.total_paw > 0 ? s.total_value_allocated / s.total_paw : 0);

  const projectPawTotals = useMemo(() => {
    let main = 0, sub = 0, unalloc = 0, paw = 0;
    for (const p of filteredProjects) {
      paw += p.paw;
      main += p.main_allocated;
      sub += sumSubcontractors(p);
      unalloc += p.remaining_workload;
    }
    return { main, sub, unalloc, paw };
  }, [filteredProjects]);

  const companyRevenueTotals = useMemo(() => {
    let turnoverStart = 0, used = 0, spare = 0;
    for (const c of filteredCompanies) {
      const t0 = Number(c.initial_turnover) || 0;
      const t1 = Number(c.turnover) || 0;
      turnoverStart += t0;
      used += t0 - t1;
      spare += t1;
    }
    return { turnoverStart, used, spare, n: filteredCompanies.length };
  }, [filteredCompanies]);

  const trendProjectPaw = useMemo(() => years.map(y => {
    const projs = regionFilter
      ? run[y].projects.filter(p => p.region === regionFilter)
      : run[y].projects;
    let paw = 0, main = 0, sub = 0, un = 0;
    for (const p of projs) {
      paw += p.paw;
      main += p.main_allocated;
      sub += sumSubcontractors(p);
      un += p.remaining_workload;
    }
    const pct = (x) => (paw > 0 ? (x / paw) * 100 : 0);
    return { mainPct: pct(main), subPct: pct(sub), unPct: pct(un), paw };
  }), [years, run, regionFilter]);

  const trendCompanyRevenue = useMemo(() => years.map(y => {
    const comps = regionFilter
      ? run[y].companies.filter(c => c.region === regionFilter)
      : run[y].companies;
    let turnoverStart = 0, used = 0;
    for (const c of comps) {
      const t0 = Number(c.initial_turnover) || 0;
      const t1 = Number(c.turnover) || 0;
      turnoverStart += t0;
      used += t0 - t1;
    }
    return { utilPct: turnoverStart > 0 ? (used / turnoverStart) * 100 : 0, turnoverStart };
  }), [years, run, regionFilter]);

  const stackedProjectByCategory = useMemo(() =>
    ABM.PROJECT_CATEGORIES.map(cat => {
      let main = 0, sub = 0, unalloc = 0;
      for (const p of filteredProjects) {
        if (p.category !== cat) continue;
        main += p.main_allocated;
        sub += sumSubcontractors(p);
        unalloc += p.remaining_workload;
      }
      return {
        label: cat,
        segments: [
          { value: main, color: 'var(--ink)', label: 'Main' },
          { value: sub, color: SEG_SUB_COLOR, label: 'Sub' },
          { value: unalloc, color: 'var(--accent)', label: 'Unallocated' },
        ],
      };
    }),
  [filteredProjects]);

  const stackedProjectByRegion = useMemo(() =>
    ABM.REGIONS.map(r => {
      let main = 0, sub = 0, unalloc = 0;
      for (const p of filteredProjects) {
        if (p.region !== r.name) continue;
        main += p.main_allocated;
        sub += sumSubcontractors(p);
        unalloc += p.remaining_workload;
      }
      return {
        label: r.name,
        segments: [
          { value: main, color: 'var(--ink)', label: 'Main' },
          { value: sub, color: SEG_SUB_COLOR, label: 'Sub' },
          { value: unalloc, color: 'var(--accent)', label: 'Unallocated' },
        ],
      };
    }),
  [filteredProjects]);

  const stackedCompanyByCategory = useMemo(() =>
    ABM.COMPANY_CATEGORIES.map(def => {
      let used = 0, spare = 0;
      for (const c of filteredCompanies) {
        if (c.category !== def.name) continue;
        const t0 = Number(c.initial_turnover) || 0;
        const t1 = Number(c.turnover) || 0;
        used += t0 - t1;
        spare += t1;
      }
      return {
        label: def.name,
        segments: [
          { value: used, color: 'var(--ink)', label: 'Utilised' },
          { value: spare, color: 'var(--accent)', label: 'Remaining' },
        ],
      };
    }),
  [filteredCompanies]);

  const stackedCompanyByRegion = useMemo(() =>
    ABM.REGIONS.map(r => {
      let used = 0, spare = 0;
      for (const c of filteredCompanies) {
        if (c.region !== r.name) continue;
        const t0 = Number(c.initial_turnover) || 0;
        const t1 = Number(c.turnover) || 0;
        used += t0 - t1;
        spare += t1;
      }
      return {
        label: r.name,
        segments: [
          { value: used, color: 'var(--ink)', label: 'Utilised' },
          { value: spare, color: 'var(--accent)', label: 'Remaining' },
        ],
      };
    }),
  [filteredCompanies]);

  const regionStats = useMemo(() =>
    ABM.REGIONS.map(r => ({
      name: r.name,
      island: r.island,
      unassigned: filteredProjects.filter(p => p.region === r.name && p.main_contractor_id == null).length,
    })),
  [filteredProjects]);

  const mapProjectAllocRegions = useMemo(() =>
    ABM.REGIONS.map(r => {
      let main = 0, sub = 0, unalloc = 0;
      for (const p of filteredProjects) {
        if (p.region !== r.name) continue;
        main += p.main_allocated;
        sub += sumSubcontractors(p);
        unalloc += p.remaining_workload;
      }
      const total = main + sub + unalloc;
      return {
        name: r.name,
        island: r.island,
        value: total,
        scalarForFill: total > 0 ? unalloc / total : 0,
        segments: [
          { value: main, color: 'var(--ink)', label: 'Main' },
          { value: sub, color: SEG_SUB_COLOR, label: 'Sub' },
          { value: unalloc, color: 'var(--accent)', label: 'Unallocated' },
        ],
      };
    }),
  [filteredProjects]);

  const mapCompanyUtilRegions = useMemo(() =>
    ABM.REGIONS.map(r => {
      let used = 0, spare = 0, turnoverStart = 0;
      for (const c of filteredCompanies) {
        if (c.region !== r.name) continue;
        const t0 = Number(c.initial_turnover) || 0;
        const t1 = Number(c.turnover) || 0;
        turnoverStart += t0;
        used += t0 - t1;
        spare += t1;
      }
      return {
        name: r.name,
        island: r.island,
        value: turnoverStart,
        scalarForFill: turnoverStart > 0 ? spare / turnoverStart : 0,
        segments: [
          { value: used, color: 'var(--ink)', label: 'Utilised' },
          { value: spare, color: 'var(--accent)', label: 'Remaining' },
        ],
      };
    }),
  [filteredCompanies]);

  const topUnassigned = filteredProjects
    .filter(p => p.main_contractor_id == null)
    .sort((a,b) => b.value - a.value)
    .slice(0, 8);

  const topSpare = cur.companies
    .filter(c => (Number(c.turnover) || 0) > 1)
    .sort((a,b) => (Number(b.turnover) || 0) - (Number(a.turnover) || 0))
    .slice(0, 6);

  const catBreakdown = ABM.PROJECT_CATEGORIES.map(c => ({
    label: c,
    value: filteredProjects
      .filter(p => p.category === c && p.main_contractor_id == null)
      .reduce((s,p)=>s+p.paw, 0),
  })).sort((a,b)=>b.value-a.value);

  const pt = projectPawTotals;
  const pawDenom = pt.paw > 0 ? pt.paw : 1;
  const ct = companyRevenueTotals;
  const turnoverDenom = ct.turnoverStart > 0 ? ct.turnoverStart : 1;

  const section01 = metricMode === 'deficit'
    ? {
        h2: 'Where the deficit lies',
        sub: `Unassigned projects clustered by region. Pin radius scales to the count of projects without a main contractor in ${year}.`,
      }
    : metricMode === 'projectAlloc'
      ? {
          h2: 'Workload split by channel',
          sub: `Annual workload (PAW) awarded through main contractors, subcontractors, or left unallocated — by geography and project category in ${year}.`,
        }
      : {
          h2: 'Firm turnover utilisation',
          sub: `Share of firm turnover (annual revenue) utilised versus remaining after allocation — by contractor category and region in ${year}. CAC applies only to main-contractor eligibility in the simulation, not these KPIs.`,
        };

  return (
    <div>
      <div className="hero">
        <div className="hero-metric-bar">
          <span className="hero-metric-bar-label" id="hero-metric-label">Overview view</span>
          <div className="hero-metric-mode" role="tablist" aria-labelledby="hero-metric-label">
            {[
              ['deficit', 'Deficit & unassigned'],
              ['projectAlloc', 'Project annual workload split'],
              ['companyUtil', 'Firm capacity split'],
            ].map(([id, lab]) => (
              <button key={id} type="button" role="tab" aria-selected={metricMode === id}
                      className={metricMode === id ? 'active' : ''}
                      onClick={() => setMetricMode(id)}>{lab}</button>
            ))}
          </div>
        </div>

        <div className="hero-left">
          <div className="hero-lede">
            <p style={{ fontSize: 10.5, fontWeight: 600, letterSpacing: '.14em', textTransform: 'uppercase', color: 'var(--accent)', margin: 0 }}>
              ALLOCATION REPORT · YEAR {year}{regionFilter ? ` · ${ABM.REGIONS.find(r=>r.name===regionFilter)?.name ?? ''}` : ''}
            </p>
            {metricMode === 'deficit' && (
              <>
                <h1 className="hero-headline">
                  <span className="accent">{fm.fmtNum(fUnassigned)}</span> of {fm.fmtNum(fTotal)} projects <em>could not find a main contractor</em> this year.
                </h1>
                <p className="hero-deck">
                  Across the simulated pipeline, <b>{fm.fmtPct(fAllocPct, 1)}</b> of annual workload was awarded to a primary or subcontracting firm. The deficit concentrates in <b>{topByCat(catBreakdown)}</b>—category capacity is binding before regional eligibility.
                </p>
              </>
            )}
            {metricMode === 'projectAlloc' && (
              <>
                <h1 className="hero-headline">
                  <span className="accent">{fm.fmtPct(pt.main / pawDenom, 1)}</span> of project annual workload is done by <em>main contractors</em>,
                  {' '}<b>{fm.fmtPct(pt.sub / pawDenom, 1)}</b> via subcontractors,
                  {' '}<span className="accent">{fm.fmtPct(pt.unalloc / pawDenom, 1)}</span> still <em>unallocated</em>.
                </h1>
                <p className="hero-deck">
                  Out of <b>{fm.fmtMoney(pt.paw)}</b> total annual workload in view, <b>{fm.fmtMoney(pt.main)}</b> sits with mains, <b>{fm.fmtMoney(pt.sub)}</b> with subcontractors, and <b>{fm.fmtMoney(pt.unalloc)}</b> remains unmatched. Use the charts to see how the mix varies by category and region.
                </p>
              </>
            )}
            {metricMode === 'companyUtil' && (
              <>
                <h1 className="hero-headline">
                  <span className="accent">{fm.fmtPct(ct.used / turnoverDenom, 1)}</span> of firms' capacity is <em>utilised</em>,
                  {' '}<b>{fm.fmtPct(ct.spare / turnoverDenom, 1)}</b> <em>remaining capacity</em> after allocation.
                </h1>
                <p className="hero-deck">
                  Across <b>{fm.fmtNum(ct.n)}</b> firms in view, start-of-year turnover totals <b>{fm.fmtMoney(ct.turnoverStart)}</b> with <b>{fm.fmtMoney(ct.used)}</b> utilised and <b>{fm.fmtMoney(ct.spare)}</b> still on the books. Regional pins show remaining share; bars break down utilised vs remaining by category and region.
                </p>
              </>
            )}
          </div>
        </div>

        {metricMode === 'deficit' && (
          <div className="kpi-strip" style={{ '--cols': 2 }}>
            <div className="kpi">
              <span className="k-label">Unassigned projects</span>
              <span className="k-value accent">{fm.fmtNum(s.projects_unassigned)}</span>
              <span className="k-sub">{fm.fmtPctRaw(100 * s.projects_unassigned / Math.max(s.total_projects, 1))} of {fm.fmtNum(s.total_projects)}</span>
              <div className="k-spark"><Chart.Sparkline values={trend.map(t=>t.unassigned)} alt /></div>
            </div>
            <div className="kpi">
              <span className="k-label">With main contractor</span>
              <span className="k-value">{fm.fmtNum(s.projects_with_main)}</span>
              <span className="k-sub">{fm.fmtPctRaw(100 * s.projects_with_main / Math.max(s.total_projects, 1))} of total</span>
              <div className="k-spark"><Chart.Sparkline values={trend.map(t=>t.fully)} /></div>
            </div>
          </div>
        )}

        {metricMode === 'projectAlloc' && (
          <div className="kpi-strip">
            <div className="kpi">
              <span className="k-label">PAW via main</span>
              <span className="k-value">{fm.fmtPct(pt.main / pawDenom, 1)}</span>
              <span className="k-sub">{fm.fmtMoney(pt.main)} of {fm.fmtMoney(pt.paw)}</span>
              <div className="k-spark"><Chart.Sparkline values={trendProjectPaw.map(t => t.mainPct)} /></div>
            </div>
            <div className="kpi">
              <span className="k-label">PAW via subs</span>
              <span className="k-value">{fm.fmtPct(pt.sub / pawDenom, 1)}</span>
              <span className="k-sub">{fm.fmtMoney(pt.sub)} awarded to subcontractors</span>
              <div className="k-spark"><Chart.Sparkline values={trendProjectPaw.map(t => t.subPct)} alt /></div>
            </div>
            <div className="kpi">
              <span className="k-label">PAW unallocated</span>
              <span className="k-value accent">{fm.fmtPct(pt.unalloc / pawDenom, 1)}</span>
              <span className="k-sub">{fm.fmtMoney(pt.unalloc)} remaining</span>
              <div className="k-spark"><Chart.Sparkline values={trendProjectPaw.map(t => t.unPct)} /></div>
            </div>
            <div className="kpi">
              <span className="k-label">Total PAW</span>
              <span className="k-value">{fm.fmtMoney(pt.paw)}</span>
              <span className="k-sub">{fm.fmtNum(filteredProjects.length)} projects in view</span>
              <div className="k-spark"><Chart.Sparkline values={trendProjectPaw.map(t => t.paw)} /></div>
            </div>
          </div>
        )}

        {metricMode === 'companyUtil' && (
          <div className="kpi-strip">
            <div className="kpi">
              <span className="k-label">Turnover utilised</span>
              <span className="k-value">{fm.fmtPct(ct.used / turnoverDenom, 1)}</span>
              <span className="k-sub">{fm.fmtMoney(ct.used)} of {fm.fmtMoney(ct.turnoverStart)}</span>
              <div className="k-spark"><Chart.Sparkline values={trendCompanyRevenue.map(t => t.utilPct)} /></div>
            </div>
            <div className="kpi">
              <span className="k-label">Turnover remaining</span>
              <span className="k-value accent">{fm.fmtPct(ct.spare / turnoverDenom, 1)}</span>
              <span className="k-sub">{fm.fmtMoney(ct.spare)} not yet allocated to workload</span>
              <div className="k-spark"><Chart.Sparkline values={trendCompanyRevenue.map(t => 100 - t.utilPct)} alt /></div>
            </div>
            <div className="kpi">
              <span className="k-label">Firms in view</span>
              <span className="k-value">{fm.fmtNum(ct.n)}</span>
              <span className="k-sub">After allocation pass</span>
              <div className="k-spark"><Chart.Sparkline values={trend.map((_, i) => {
                const comps = regionFilter
                  ? run[years[i]].companies.filter(c => c.region === regionFilter)
                  : run[years[i]].companies;
                return comps.length;
              })} /></div>
            </div>
            <div className="kpi">
              <span className="k-label">Total start turnover</span>
              <span className="k-value">{fm.fmtMoney(ct.turnoverStart)}</span>
              <span className="k-sub">Sum of firms’ revenue at year open</span>
              <div className="k-spark"><Chart.Sparkline values={trendCompanyRevenue.map(t => t.turnoverStart)} /></div>
            </div>
          </div>
        )}
      </div>

      <div className="section-h">
        <div className="kicker">§ 01</div>
        <div>
          <h2>{section01.h2}</h2>
          <p className="sub">{section01.sub}</p>
        </div>
      </div>

      <div className="two-col">
        <div className="panel" style={{ padding: 0, background: 'var(--bg)', border: 0 }}>
          {metricMode === 'deficit' && (
            <Chart.NZMap
              regions={regionStats}
              valueFn={(r) => r.unassigned}
              format={(v) => (v ? `${v} projects` : '')}
              onSelect={(name) => setRegionFilter(regionFilter === name ? null : name)}
              selected={regionFilter}
            />
          )}
          {metricMode === 'projectAlloc' && (
            <Chart.NZMap
              regions={mapProjectAllocRegions}
              valueFn={(r) => r.value}
              fillFn={(r) => r.scalarForFill}
              format={(v) => fm.fmtMoney(v)}
              onSelect={(name) => setRegionFilter(regionFilter === name ? null : name)}
              selected={regionFilter}
            />
          )}
          {metricMode === 'companyUtil' && (
            <Chart.NZMap
              regions={mapCompanyUtilRegions}
              valueFn={(r) => r.value}
              fillFn={(r) => r.scalarForFill}
              format={(v) => fm.fmtMoney(v)}
              onSelect={(name) => setRegionFilter(regionFilter === name ? null : name)}
              selected={regionFilter}
            />
          )}
          {(metricMode === 'projectAlloc' || metricMode === 'companyUtil') && (
            <div className="map-legend map-legend--segments">
              {metricMode === 'projectAlloc' && (
                <>
                  <span><i className="sw" style={{ background: 'var(--ink)' }} /> Main</span>
                  <span><i className="sw" style={{ background: SEG_SUB_COLOR }} /> Sub</span>
                  <span><i className="sw" style={{ background: 'var(--accent)' }} /> Unallocated</span>
                </>
              )}
              {metricMode === 'companyUtil' && (
                <>
                  <span><i className="sw" style={{ background: 'var(--ink)' }} /> Utilised</span>
                  <span><i className="sw" style={{ background: 'var(--accent)' }} /> Remaining</span>
                </>
              )}
            </div>
          )}
          {regionFilter && (
            <div style={{ textAlign: 'center', fontSize: 11, color: 'var(--ink-3)', marginTop: 8 }}>
              Filtering all views by {ABM.REGIONS.find(r=>r.name===regionFilter)?.name}.
              <button className="btn ghost" style={{ marginLeft: 10, padding: '4px 10px', fontSize: 10 }}
                      onClick={() => setRegionFilter(null)}>Clear</button>
            </div>
          )}
        </div>

        <div>
          {metricMode === 'deficit' && (
            <div className="panel">
              <div className="panel-h">
                <h3>Unassigned annual workload, by category</h3>
                <span className="meta">PAW · {year}</span>
              </div>
              <Chart.BarChart
                data={catBreakdown}
                width={620} height={210}
                format={fm.fmtMoney} alt
              />
            </div>
          )}

          {metricMode === 'projectAlloc' && (
            <>
              <div className="panel">
                <div className="panel-h">
                  <h3>PAW split by project category</h3>
                  <span className="meta">Main · Sub · Unallocated · {year}</span>
                </div>
                <Chart.StackedBarChartRows
                  data={stackedProjectByCategory}
                  width={620} height={220}
                  format={fm.fmtMoney}
                />
              </div>
              <div className="panel" style={{ marginTop: 14 }}>
                <div className="panel-h">
                  <h3>PAW split by region</h3>
                  <span className="meta">Same breakdown · {year}</span>
                </div>
                <Chart.StackedBarChartRows
                  data={stackedProjectByRegion}
                  width={620} height={200}
                  format={fm.fmtMoney}
                />
              </div>
            </>
          )}

          {metricMode === 'companyUtil' && (
            <>
              <div className="panel">
                <div className="panel-h">
                  <h3>Turnover by contractor category</h3>
                  <span className="meta">Utilised vs remaining turnover · {year}</span>
                </div>
                <Chart.StackedBarChartRows
                  data={stackedCompanyByCategory}
                  width={620} height={240}
                  format={fm.fmtMoney}
                />
              </div>
              <div className="panel" style={{ marginTop: 14 }}>
                <div className="panel-h">
                  <h3>Turnover by region</h3>
                  <span className="meta">Same breakdown · {year}</span>
                </div>
                <Chart.StackedBarChartRows
                  data={stackedCompanyByRegion}
                  width={620} height={200}
                  format={fm.fmtMoney}
                />
              </div>
            </>
          )}
        </div>
      </div>

      {showUnassigned && (
        <>
          <div className="section-h">
            <div className="kicker">§ 02</div>
            <div>
              <h2>Top unassigned projects</h2>
              <p className="sub">The eight largest projects that could not be matched to any main contractor under current capacity. Click for the full eligibility trace.</p>
            </div>
          </div>
          <div className="panel">
            <table className="dt">
              <thead>
                <tr>
                  <th>Project</th>
                  <th>Category</th>
                  <th>Region</th>
                  <th className="num">Value</th>
                  <th className="num">PAW</th>
                  <th className="num">Years</th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {topUnassigned.map(p => (
                  <tr key={p.project_id} className="clickable" onClick={() => onOpenProject(p)}>
                    <td className="label">{p.name}</td>
                    <td><span className="tag">{p.category}</span></td>
                    <td className="dim">{ABM.REGIONS.find(r=>r.name===p.region)?.name ?? p.region}</td>
                    <td className="num">{fm.fmtMoney(p.value)}</td>
                    <td className="num">{fm.fmtMoney(p.paw)}</td>
                    <td className="num dim">{p.duration}</td>
                    <td className="num dim">→</td>
                  </tr>
                ))}
                {topUnassigned.length === 0 && (
                  <tr><td colSpan="7" style={{ textAlign:'center', padding:24, color:'var(--ink-3)' }}>No unassigned projects in this filter.</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </>
      )}

      <div className="section-h">
        <div className="kicker">§ {showUnassigned ? '03' : '02'}</div>
        <div>
          <h2>Firms with remaining turnover</h2>
          <p className="sub">Companies whose turnover after allocation is still positive — ranked by remaining revenue. Dashboard firm KPIs use turnover; CAC/RAC are simulation mechanics (main-contractor size gate).</p>
        </div>
      </div>

      <div className="three-col">
        {topSpare.map(c => {
          const t0 = Number(c.initial_turnover) || 0;
          const t1 = Number(c.turnover) || 0;
          const awarded = t0 - t1;
          return (
          <div key={c.company_id} className="panel">
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'baseline' }}>
              <div>
                <div style={{ fontFamily:'var(--serif)', fontSize:18, fontWeight:500 }}>{c.name}</div>
                <div style={{ fontSize:11, color:'var(--ink-3)', marginTop:2 }}>
                  <span className="tag">{c.category}</span>
                  {' · '}{c.size_band}
                  {' · '}{c.reach}
                </div>
              </div>
              <span className={`pill ${c.role === 'main' ? 'partial' : 'full'}`}>
                {c.role === 'main' ? 'Main' : 'Sub'}
              </span>
            </div>
            <div style={{ marginTop:14 }}>
              <Chart.StackedBar
                segments={[
                  { value: Math.max(awarded, 0), color: 'var(--ink)', label: 'Utilised' },
                  { value: Math.max(t1, 0), color: 'var(--accent)', label: 'Remaining' },
                ]}
                height={20} format={fm.fmtMoney}
              />
              <div style={{ display:'flex', justifyContent:'space-between', marginTop:6, fontSize:10.5, color:'var(--ink-3)', fontVariantNumeric:'tabular-nums' }}>
                <span>Utilised {fm.fmtMoney(awarded)}</span>
                <span>Remaining {fm.fmtMoney(t1)}</span>
              </div>
            </div>
          </div>
          );
        })}
      </div>
    </div>
  );
}

function topByCat(cats) {
  const sorted = [...cats].sort((a,b)=>b.value-a.value);
  if (!sorted[0] || sorted[0].value === 0) return 'no single category';
  return sorted[0].label.toLowerCase();
}

