// Charts: small SVG-based primitives. No external libs.
// Exports: BarChart, LineChart, Sparkline, Donut, StackedBar, StackedBarChartRows, NZMap

import React from 'react';
import { NZ_GEO } from './nz-geo.js';

function tickValues(min, max, count = 5) {
  const span = max - min || 1;
  const raw = span / count;
  const mag = Math.pow(10, Math.floor(Math.log10(raw)));
  const norm = raw / mag;
  let step;
  if (norm < 1.5) step = 1 * mag;
  else if (norm < 3) step = 2 * mag;
  else if (norm < 7) step = 5 * mag;
  else step = 10 * mag;
  const start = Math.ceil(min / step) * step;
  const out = [];
  for (let v = start; v <= max + 1e-9; v += step) out.push(v);
  return out;
}

export function BarChart({ data, width = 480, height = 240, format = (v) => v, alt = false, valueLabel = '' }) {
  const padL = 140, padR = 60, padT = 8, padB = 14;
  const max = Math.max(...data.map(d => d.value), 1);
  const rowH = (height - padT - padB) / Math.max(data.length, 1);
  return (
    <svg className="chart-svg" viewBox={`0 0 ${width} ${height}`} preserveAspectRatio="none">
      {data.map((d, i) => {
        const y = padT + i * rowH;
        const w = (d.value / max) * (width - padL - padR);
        return (
          <g key={i}>
            <text x={padL - 8} y={y + rowH / 2} textAnchor="end" dominantBaseline="middle" className="lbl">
              {d.label}
            </text>
            <rect x={padL} y={y + rowH * 0.15} width={Math.max(w, 1)} height={rowH * 0.7}
                  className={alt ? 'bar alt' : 'bar'} />
            <text x={padL + w + 6} y={y + rowH / 2} dominantBaseline="middle" className="tick-lbl">
              {format(d.value)}
            </text>
          </g>
        );
      })}
    </svg>
  );
}

export function LineChart({ series, width = 600, height = 240, xLabels, yFormat = (v) => v, area = true }) {
  const padL = 44, padR = 16, padT = 14, padB = 28;
  const allY = series.flatMap(s => s.points.map(p => p.y));
  const allX = series[0].points.map(p => p.x);
  const minY = 0;
  const maxY = Math.max(...allY, 1) * 1.08;
  const xs = (i) => padL + (i / Math.max(allX.length - 1, 1)) * (width - padL - padR);
  const ys = (v) => padT + (1 - (v - minY) / (maxY - minY)) * (height - padT - padB);
  const ticks = tickValues(minY, maxY, 4);

  return (
    <svg className="chart-svg" viewBox={`0 0 ${width} ${height}`} preserveAspectRatio="none">
      {ticks.map((t, i) => (
        <g key={'g'+i}>
          <line x1={padL} x2={width - padR} y1={ys(t)} y2={ys(t)} className="grid" />
          <text x={padL - 6} y={ys(t)} textAnchor="end" dominantBaseline="middle" className="tick-lbl">
            {yFormat(t)}
          </text>
        </g>
      ))}
      <line x1={padL} x2={width - padR} y1={height - padB} y2={height - padB} className="axis" />
      {allX.map((x, i) => (
        <text key={'x'+i} x={xs(i)} y={height - padB + 14} textAnchor="middle" className="tick-lbl">
          {xLabels ? xLabels[i] : x}
        </text>
      ))}
      {series.map((s, si) => {
        const pts = s.points.map((p, i) => `${xs(i)},${ys(p.y)}`).join(' ');
        const areaPath = `M${xs(0)},${ys(0)} L${pts.split(' ').join(' L')} L${xs(s.points.length - 1)},${ys(0)} Z`;
        return (
          <g key={si}>
            {area && si === 0 && <path d={areaPath} className="area" />}
            <polyline points={pts} className={si === 0 ? 'line alt' : 'line'} />
            {s.points.map((p, i) => (
              <circle key={i} cx={xs(i)} cy={ys(p.y)} r={3}
                      fill={si === 0 ? 'var(--accent)' : 'var(--ink)'} />
            ))}
          </g>
        );
      })}
    </svg>
  );
}

export function Sparkline({ values, width = 120, height = 28, alt = false }) {
  if (!values || !values.length) return null;
  const min = Math.min(...values), max = Math.max(...values);
  const span = max - min || 1;
  const xs = (i) => (i / Math.max(values.length - 1, 1)) * width;
  const ys = (v) => height - ((v - min) / span) * height * 0.85 - 2;
  const pts = values.map((v, i) => `${xs(i)},${ys(v)}`).join(' ');
  return (
    <svg className="chart-svg" viewBox={`0 0 ${width} ${height}`}>
      <polyline points={pts} fill="none"
                stroke={alt ? 'var(--accent)' : 'var(--ink)'} strokeWidth="1.25" />
      <circle cx={xs(values.length - 1)} cy={ys(values[values.length - 1])} r={2.5}
              fill={alt ? 'var(--accent)' : 'var(--ink)'} />
    </svg>
  );
}

export function Donut({ value, total, size = 120, label }) {
  const pct = total > 0 ? value / total : 0;
  const r = size / 2 - 8;
  const c = size / 2;
  const circ = 2 * Math.PI * r;
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <circle cx={c} cy={c} r={r} fill="none"
              stroke="var(--rule)" strokeWidth="6" />
      <circle cx={c} cy={c} r={r} fill="none"
              stroke="var(--accent)" strokeWidth="6"
              strokeDasharray={`${pct * circ} ${circ}`}
              transform={`rotate(-90 ${c} ${c})`}
              strokeLinecap="butt" />
      <text x={c} y={c - 2} textAnchor="middle" fontFamily="var(--serif)"
            fontSize={size * 0.28} fill="var(--ink)" fontVariantNumeric="tabular-nums">
        {(pct * 100).toFixed(0)}%
      </text>
      {label && (
        <text x={c} y={c + size * 0.18} textAnchor="middle" fontFamily="var(--sans)"
              fontSize="9" fontWeight="600" letterSpacing="1.5px"
              fill="var(--ink-3)">
          {label.toUpperCase()}
        </text>
      )}
    </svg>
  );
}

export function StackedBarChartRows({
  data,
  width = 620,
  height = 240,
  format = (v) => v,
  minPctLabel = 9,
  /** ViewBox units reserved for row labels (long contractor category names need space). */
  padL = 228,
}) {
  const padR = 8, padT = 6, padB = 10;
  const n = Math.max(data.length, 1);
  const rowH = (height - padT - padB) / n;
  const barW = width - padL - padR;
  return (
    <svg className="chart-svg" viewBox={`0 0 ${width} ${height}`} preserveAspectRatio="none">
      {data.map((row, i) => {
        const y = padT + i * rowH;
        const midY = y + rowH / 2;
        const total = row.segments.reduce((s, x) => s + Math.max(0, x.value), 0) || 1;
        let x0 = padL;
        return (
          <g key={i}>
            <text x={padL - 8} y={midY} textAnchor="end" dominantBaseline="middle" className="lbl">
              {row.label}
            </text>
            {row.segments.map((seg, j) => {
              const w = (Math.max(0, seg.value) / total) * barW;
              const pct = (Math.max(0, seg.value) / total) * 100;
              const showLbl = pct >= minPctLabel && w > 36;
              const tx = x0 + w / 2;
              const piece = (
                <g key={j}>
                  <rect x={x0} y={y + rowH * 0.12} width={Math.max(w, 0)} height={rowH * 0.76}
                        fill={seg.color} stroke="var(--bg)" strokeWidth={w > 1 ? 0.5 : 0}>
                    <title>{`${seg.label || ''}: ${format(seg.value)} (${pct.toFixed(1)}%)`}</title>
                  </rect>
                  {showLbl && (
                    <text x={tx} y={midY} textAnchor="middle" dominantBaseline="middle"
                          className="tick-lbl" fill="var(--bg)" style={{ fontSize: 9.5, fontWeight: 600 }}>
                      {format(seg.value)}
                    </text>
                  )}
                </g>
              );
              x0 += w;
              return piece;
            })}
          </g>
        );
      })}
    </svg>
  );
}

export function StackedBar({ segments, height = 24, format = (v) => v }) {
  const total = segments.reduce((s, x) => s + x.value, 0) || 1;
  return (
    <div style={{ display: 'flex', height, border: '1px solid var(--ink)' }}>
      {segments.map((s, i) => {
        const w = (s.value / total) * 100;
        if (w < 0.01) return null;
        return (
          <div key={i} title={`${s.label}: ${format(s.value)}`}
               style={{
                 flex: `${w} 0 0`,
                 background: s.color,
                 borderRight: i < segments.length - 1 ? '1px solid var(--bg)' : 0,
                 display: 'flex', alignItems: 'center', justifyContent: 'center',
                 color: 'var(--bg)', fontSize: 10, fontWeight: 600,
                 overflow: 'hidden', whiteSpace: 'nowrap',
               }}>
            {w > 8 ? format(s.value) : ''}
          </div>
        );
      })}
    </div>
  );
}

const COUNCIL_TO_SIM = {
  'Auckland':              'Auckland Region',
  'Waikato':               'Waikato Region',
  'Wellington':            'Wellington Region',
  'Northland':             'Rest of North Island',
  'Bay of Plenty':         'Rest of North Island',
  'Gisborne District':     'Rest of North Island',
  "Hawke's Bay":           'Rest of North Island',
  'Taranaki':              'Rest of North Island',
  'Manawatu-Wanganui':     'Rest of North Island',
  'Canterbury':            'Canterbury Region',
  'Marlborough District':  'Rest of South Island',
  'Nelson City':           'Rest of South Island',
  'Tasman District':       'Rest of South Island',
  'West Coast':            'Rest of South Island',
  'Otago':                 'Rest of South Island',
  'Southland':             'Rest of South Island',
};

function annularSectorPath(cx, cy, rOut, rIn, a0Deg, a1Deg) {
  const s0 = ((a0Deg - 90) * Math.PI) / 180;
  const s1 = ((a1Deg - 90) * Math.PI) / 180;
  const xo0 = cx + rOut * Math.cos(s0), yo0 = cy + rOut * Math.sin(s0);
  const xo1 = cx + rOut * Math.cos(s1), yo1 = cy + rOut * Math.sin(s1);
  const xi0 = cx + rIn * Math.cos(s1), yi0 = cy + rIn * Math.sin(s1);
  const xi1 = cx + rIn * Math.cos(s0), yi1 = cy + rIn * Math.sin(s0);
  const large = a1Deg - a0Deg > 180 ? 1 : 0;
  return `M ${xo0} ${yo0} A ${rOut} ${rOut} 0 ${large} 1 ${xo1} ${yo1} L ${xi0} ${yi0} A ${rIn} ${rIn} 0 ${large} 0 ${xi1} ${yi1} Z`;
}

export function NZMap({ regions, valueFn, format = (v) => v, onSelect, selected, fillFn }) {
  const geo = NZ_GEO;
  const sim = (regions || []).map(r => ({ ...r, value: valueFn ? valueFn(r) : 0 }));
  const byName = {};
  for (const r of sim) byName[r.name] = r;
  const maxV = Math.max(1, ...sim.map(p => p.value || 0));

  if (!geo) return <svg className="nz-map" viewBox="0 0 320 600" />;

  const pinAnchors = {
    'Auckland Region':      'NZAUK',
    'Waikato Region':       'NZWKO',
    'Wellington Region':    'NZWGN',
    'Rest of North Island': 'NZMWT',
    'Canterbury Region':    'NZCAN',
    'Rest of South Island': 'NZOTA',
  };

  const colorFor = (simName) => {
    const row = byName[simName];
    if (fillFn && row) {
      const t = fillFn(row);
      if (t != null && Number.isFinite(t) && t > 0) {
        const eased = Math.sqrt(Math.min(1, Math.max(0, t)));
        return `rgba(var(--accent-rgb), ${(0.18 + 0.72 * eased).toFixed(3)})`;
      }
      return 'var(--map-fill-empty)';
    }
    const v = row?.value || 0;
    if (!v) return 'var(--map-fill-empty)';
    const t = Math.sqrt(v / maxV);
    return `rgba(var(--accent-rgb), ${(0.18 + 0.72 * t).toFixed(3)})`;
  };

  return (
    <svg className="nz-map" viewBox={`0 0 ${geo.width} ${geo.height}`}
         preserveAspectRatio="xMidYMid meet">
      {geo.regions.map(cr => {
        const simName = COUNCIL_TO_SIM[cr.name];
        const isSelected = selected && simName === selected;
        const dim = selected && simName !== selected;
        const row = byName[simName];
        const tip = row && Array.isArray(row.segments) && row.segments.length
          ? `${cr.name} — ${row.segments.map(s => `${s.label}: ${format(s.value)}`).join(' · ')}`
          : `${cr.name} — ${byName[simName]?.name ?? simName}: ${format(byName[simName]?.value || 0)}`;
        return (
          <path key={cr.id}
                d={cr.d}
                className={`nz-region${isSelected ? ' selected' : ''}${dim ? ' dim' : ''}`}
                fill={colorFor(simName)}
                onClick={() => onSelect && simName && onSelect(simName)}
                style={{ cursor: onSelect ? 'pointer' : 'default' }}>
            <title>{tip}</title>
          </path>
        );
      })}

      {sim.map(p => {
        const anchorId = pinAnchors[p.name];
        const anchor = geo.regions.find(c => c.id === anchorId);
        if (!anchor) return null;
        const dim = selected && selected !== p.name;
        const hasSeg = Array.isArray(p.segments) && p.segments.length > 0;
        const totalSeg = hasSeg
          ? p.segments.reduce((s, x) => s + Math.max(0, x.value), 0)
          : (p.value || 0);
        const r = 8 + 26 * Math.sqrt((totalSeg || 0) / maxV);
        const rOut = Math.max(10, r);
        const rIn = hasSeg ? rOut * 0.45 : 0;
        const nSeg = hasSeg ? p.segments.length : 0;
        let arcStart = 0;
        return (
          <g key={p.name} onClick={() => onSelect && onSelect(p.name)}
             style={{ cursor: onSelect ? 'pointer' : 'default', opacity: dim ? 0.35 : 1 }}>
            {!hasSeg && (
              <>
                <circle cx={anchor.cx} cy={anchor.cy} r={r}
                        className="pin" fillOpacity={selected === p.name ? 1 : 0.85} />
                <text x={anchor.cx} y={anchor.cy + 4} className="pin-num"
                      textAnchor="middle" style={{ pointerEvents:'none' }}>
                  {p.value || 0}
                </text>
              </>
            )}
            {hasSeg && totalSeg <= 0 && (
              <circle cx={anchor.cx} cy={anchor.cy} r={10}
                      fill="var(--map-fill-empty)" stroke="var(--rule)" strokeWidth="1"
                      fillOpacity={selected === p.name ? 1 : 0.85} />
            )}
            {hasSeg && totalSeg > 0 && p.segments.map((seg, si) => {
              const frac = Math.max(0, seg.value) / totalSeg;
              const a0 = arcStart;
              const a1 = si === nSeg - 1 ? 360 : arcStart + frac * 360;
              arcStart = a1;
              if (a1 - a0 < 0.05) return null;
              return (
                <path key={si}
                      d={annularSectorPath(anchor.cx, anchor.cy, rOut, rIn, a0, a1)}
                      fill={seg.color} stroke="var(--bg)" strokeWidth="0.5" fillOpacity={selected === p.name ? 1 : 0.9}>
                  <title>{`${seg.label}: ${format(seg.value)}`}</title>
                </path>
              );
            })}
            {hasSeg && totalSeg > 0 && (
              <text x={anchor.cx} y={anchor.cy + 3} className="pin-num"
                    textAnchor="middle" style={{ pointerEvents:'none', fontSize: 9 }}>
                {p.name}
              </text>
            )}
            <text x={anchor.cx + (hasSeg && totalSeg > 0 ? rOut : r) + 6} y={anchor.cy - 4} className="pin-lbl">{p.name}</text>
            <text x={anchor.cx + (hasSeg && totalSeg > 0 ? rOut : r) + 6} y={anchor.cy + 9} className="pin-val">{format(hasSeg ? totalSeg : (p.value || 0))}</text>
          </g>
        );
      })}

      <text x={geo.width * 0.78} y={geo.height * 0.12} className="island-lbl">Te Ika-a-Māui</text>
      <text x={geo.width * 0.78} y={geo.height * 0.13 + 14} className="island-lbl"
            style={{ fontSize:'11px', fontStyle:'normal', letterSpacing:'.14em' }}>NORTH ISLAND</text>
      <text x={geo.width * 0.04} y={geo.height * 0.96} className="island-lbl">Te Waipounamu</text>
      <text x={geo.width * 0.04} y={geo.height * 0.97 + 14} className="island-lbl"
            style={{ fontSize:'11px', fontStyle:'normal', letterSpacing:'.14em' }}>SOUTH ISLAND</text>
    </svg>
  );
}

export const Chart = { BarChart, LineChart, Sparkline, Donut, StackedBar, StackedBarChartRows, NZMap, tickValues };
