// Reusable formatting + small helpers

export const fmtMoney = (v) => {
  if (v == null || isNaN(v)) return '—';
  const a = Math.abs(v);
  if (a >= 1e9) return `$${(v / 1e9).toFixed(2)}B`;
  if (a >= 1e6) return `$${(v / 1e6).toFixed(1)}M`;
  if (a >= 1e3) return `$${(v / 1e3).toFixed(0)}K`;
  return `$${v.toFixed(0)}`;
};

export const fmtMoneyLong = (v) => {
  if (v == null || isNaN(v)) return '—';
  return '$' + Math.round(v).toLocaleString('en-NZ');
};

export const fmtNum = (v) => v == null ? '—' : Math.round(v).toLocaleString('en-NZ');
export const fmtPct = (v, digits = 1) => v == null ? '—' : `${(v * 100).toFixed(digits)}%`;
export const fmtPctRaw = (v, digits = 1) => v == null ? '—' : `${v.toFixed(digits)}%`;

export const fmt = { fmtMoney, fmtMoneyLong, fmtNum, fmtPct, fmtPctRaw };
