// Table 1 — in-house percentages by turnover
export function inHousePct(turnover) {
  if (turnover >= 200_000_000) return 0.10;
  if (turnover >= 100_000_000) return 0.20;
  if (turnover >=  50_000_000) return 0.20;
  if (turnover >=  20_000_000) return 0.30;
  if (turnover >=  10_000_000) return 0.30;
  if (turnover >=   5_000_000) return 0.40;
  if (turnover >=   1_000_000) return 0.50;
  if (turnover >=     100_000) return 0.60;
  return 1.0;
}

// Table 2 — operation reach
export function reach(turnover) {
  if (turnover >= 50_000_000) return 'National';
  if (turnover >=  5_000_000) return 'Multi-region';
  return 'Regional';
}

export function sizeBand(turnover) {
  if (turnover >= 200_000_000) return 'Mega ($200M+)';
  if (turnover >= 100_000_000) return 'Large ($100–200M)';
  if (turnover >=  50_000_000) return 'Large ($50–100M)';
  if (turnover >=  20_000_000) return 'Mid ($20–50M)';
  if (turnover >=  10_000_000) return 'Mid ($10–20M)';
  if (turnover >=   5_000_000) return 'Mid ($5–10M)';
  if (turnover >=   1_000_000) return 'Small ($1–5M)';
  if (turnover >=     100_000) return 'Micro ($100K–1M)';
  return 'Sole trader (<$100K)';
}

export const SIZE_BANDS_ORDER = [
  'Sole trader (<$100K)','Micro ($100K–1M)','Small ($1–5M)',
  'Mid ($5–10M)','Mid ($10–20M)','Mid ($20–50M)',
  'Large ($50–100M)','Large ($100–200M)','Mega ($200M+)',
];

// duration heuristic
export function duration(value) {
  if (value > 200_000_000) return 4;
  if (value >  50_000_000) return 3;
  if (value >  10_000_000) return 2;
  return 1;
}

