/* forecast.jsx — Resilience Hub: Forecast tab
 *
 * Layout:
 *   - Left rail: scenario inputs (GDP, Pop, Inflation, Fiscal slider, Horizon,
 *                Shocks list + add, Run forecast)
 *   - Main: per-region STACKED AREA charts (ensemble only) by building type,
 *           with shock annotations overlayed.
 */
import React, { useState, useRef } from 'react';
import { ForecastAPI, BUILDING_TYPES, SHOCK_TYPES } from './forecast-api.js';

function fmtM(v) {
  if (v >= 1000) return (v / 1000).toFixed(1) + 'B';
  if (v >= 1) return v.toFixed(0) + 'M';
  return v.toFixed(2) + 'M';
}
function fmtInt(n) { return Math.round(n).toLocaleString(); }
function fmtPct(n) { return (n >= 0 ? '+' : '') + n.toFixed(2) + '%'; }
function newId() { return 'sh_' + Math.random().toString(36).slice(2, 8); }

const BT_COLORS = {
  Residential: '#4a6b3a',
  Institutional: '#2f6fb0',
  Commercial: '#b78a2b',
  Industrial: '#b04a2f',
};

/* ─────────────────────── Stacked AREA chart (ensemble) ─────────────────────── */
function StackedAreaChart({ historical, by_building_type, activeBTs, metric, shocks, height = 200 }) {
  const W = 760, H = height, pad = { t: 18, r: 16, b: 28, l: 56 };

  const years = [];
  historical.forEach(d => years.push({ year: d.year, kind: 'hist' }));
  const anyBT = BUILDING_TYPES[0];
  by_building_type[anyBT].forecasts.ensemble.forEach(d => years.push({ year: d.year, kind: 'fc' }));

  const rows = years.map(({ year, kind }) => {
    const row = { year, kind };
    let total = 0;
    for (const bt of BUILDING_TYPES) {
      const src = kind === 'hist'
        ? by_building_type[bt].historical
        : by_building_type[bt].forecasts.ensemble;
      const rec = src.find(d => d.year === year);
      const v = rec ? rec[metric] : 0;
      row[bt] = v;
      if (activeBTs.includes(bt)) total += v;
    }
    row._total = total;
    return row;
  });

  const minY = years[0].year, maxY = years[years.length - 1].year;
  const yMax = Math.max(...rows.map(r => r._total)) * 1.10 || 1;
  const yMin = 0;

  const xS = (year) => pad.l + (year - minY) / (maxY - minY || 1) * (W - pad.l - pad.r);
  const yS = (v) => pad.t + (1 - (v - yMin) / (yMax - yMin)) * (H - pad.t - pad.b);

  const yTicks = [0, 0.25, 0.5, 0.75, 1].map(p => yMin + (yMax - yMin) * p);
  const yearTicks = [];
  for (let y = Math.ceil(minY / 5) * 5; y <= maxY; y += 5) yearTicks.push(y);

  const lastHistYear = historical[historical.length - 1].year;
  const forecastX0 = xS(lastHistYear);

  const stackOrder = BUILDING_TYPES.filter(bt => activeBTs.includes(bt));
  const cumByYear = rows.map(r => {
    const out = { year: r.year, kind: r.kind, levels: [0] };
    let cum = 0;
    for (const bt of stackOrder) {
      cum += r[bt];
      out.levels.push(cum);
    }
    return out;
  });

  function areaPath(btIndex) {
    const tops = cumByYear.map(r => `${xS(r.year)} ${yS(r.levels[btIndex + 1])}`);
    const bots = cumByYear.slice().reverse().map(r => `${xS(r.year)} ${yS(r.levels[btIndex])}`);
    return 'M' + tops.join(' L ') + ' L ' + bots.join(' L ') + ' Z';
  }

  const [hover, setHover] = useState(null);
  const svgRef = useRef(null);

  function onMove(e) {
    const rect = svgRef.current.getBoundingClientRect();
    const px = (e.clientX - rect.left) * (W / rect.width);
    let best = null, bestDist = Infinity;
    for (const r of rows) {
      const d = Math.abs(xS(r.year) - px);
      if (d < bestDist) { bestDist = d; best = r; }
    }
    if (best && bestDist < (W - pad.l - pad.r) / years.length * 0.7) setHover(best);
    else setHover(null);
  }

  const shockBands = (shocks || []).map(sh => {
    const y0 = Math.max(minY, sh.year);
    const y1 = Math.min(maxY, sh.year + Math.max(1, sh.duration) - 1);
    if (y1 < y0) return null;
    return {
      ...sh,
      x0: xS(y0),
      x1: xS(y1),
      label: (SHOCK_TYPES[sh.type]?.label || 'Shock'),
    };
  }).filter(Boolean);

  return (
    <div style={{ position: 'relative' }}>
      <svg ref={svgRef} viewBox={`0 0 ${W} ${H}`} className="chart-svg"
           style={{ height, display: 'block' }}
           onMouseMove={onMove} onMouseLeave={() => setHover(null)}>

        <defs>
          <pattern id="hatch-shock" patternUnits="userSpaceOnUse" width="6" height="6" patternTransform="rotate(45)">
            <line x1="0" y1="0" x2="0" y2="6" stroke="var(--bad)" strokeWidth="1.5" opacity="0.5" />
          </pattern>
          <pattern id="hatch-boost" patternUnits="userSpaceOnUse" width="6" height="6" patternTransform="rotate(45)">
            <line x1="0" y1="0" x2="0" y2="6" stroke="var(--good)" strokeWidth="1.5" opacity="0.5" />
          </pattern>
        </defs>

        {/* forecast shaded background */}
        <rect x={forecastX0} y={pad.t} width={Math.max(0, xS(maxY) - forecastX0)} height={H - pad.t - pad.b}
              fill="var(--bg-alt)" opacity="0.7" />
        <text x={forecastX0 + 4} y={pad.t + 11} className="lbl"
              style={{ fontSize: 9.5, fill: 'var(--ink-3)', letterSpacing: '.1em', textTransform: 'uppercase' }}>
          FORECAST · ENSEMBLE
        </text>

        {/* grid + axes */}
        {yTicks.map((v, i) => (
          <g key={'yt' + i}>
            <line className="grid" x1={pad.l} x2={W - pad.r} y1={yS(v)} y2={yS(v)} />
            <text className="tick-lbl" x={pad.l - 6} y={yS(v) + 3} textAnchor="end">
              {metric === 'value' ? fmtM(v) : fmtInt(v)}
            </text>
          </g>
        ))}
        {yearTicks.map(y => (
          <text key={'xt' + y} className="tick-lbl" x={xS(y)} y={H - pad.b + 14} textAnchor="middle">{y}</text>
        ))}
        <line className="axis" x1={pad.l} x2={W - pad.r} y1={H - pad.b} y2={H - pad.b} />

        {/* stacked areas */}
        {stackOrder.map((bt, i) => (
          <path key={bt} d={areaPath(i)}
                fill={BT_COLORS[bt]} opacity="0.78"
                stroke={BT_COLORS[bt]} strokeWidth="0.6" />
        ))}

        {/* shock annotations: vertical hatched bands + label */}
        {shockBands.map(sh => {
          const neg = sh.magnitude < 0;
          const fillId = neg ? 'url(#hatch-shock)' : 'url(#hatch-boost)';
          const lineColor = neg ? 'var(--bad)' : 'var(--good)';
          const bandW = Math.max(8, sh.x1 - sh.x0);
          return (
            <g key={sh.id}>
              <rect x={sh.x0} y={pad.t} width={bandW} height={H - pad.t - pad.b}
                    fill={fillId} />
              <line x1={sh.x0} x2={sh.x0} y1={pad.t} y2={H - pad.b}
                    stroke={lineColor} strokeWidth="1.2" />
              {sh.x1 > sh.x0 + 2 && (
                <line x1={sh.x0 + bandW} x2={sh.x0 + bandW} y1={pad.t} y2={H - pad.b}
                      stroke={lineColor} strokeWidth="1.2" strokeDasharray="2 2" />
              )}
              <g transform={`translate(${sh.x0 + 3}, ${pad.t + 22})`}>
                <text style={{ fontSize: 9, fontWeight: 700, letterSpacing: '.08em', textTransform: 'uppercase' }}
                      fill={lineColor}>
                  {sh.label}
                </text>
                <text style={{ fontSize: 9, fill: 'var(--ink-2)', fontFamily: 'var(--mono)' }}
                      y={11}>
                  {sh.year}{sh.duration > 1 ? `→${sh.year + sh.duration - 1}` : ''} · {sh.magnitude > 0 ? '+' : ''}{sh.magnitude}%
                </text>
              </g>
            </g>
          );
        })}

        {/* hover marker */}
        {hover && (
          <line x1={xS(hover.year)} x2={xS(hover.year)} y1={pad.t} y2={H - pad.b}
                stroke="var(--ink)" strokeWidth="0.8" opacity="0.4" />
        )}
      </svg>

      {hover && (
        <div style={{
          position: 'absolute',
          left: Math.min(Math.max(0, (xS(hover.year) / W) * 100), 78) + '%',
          top: 6,
          transform: 'translateX(8px)',
          background: 'var(--bg)',
          border: '1px solid var(--ink)',
          padding: '8px 10px',
          fontSize: 11,
          fontFamily: 'var(--mono)',
          minWidth: 170,
          boxShadow: '2px 2px 0 rgba(0,0,0,0.08)',
          pointerEvents: 'none',
          zIndex: 5,
        }}>
          <div style={{ fontWeight: 700, marginBottom: 4 }}>
            {hover.year} {hover.kind === 'fc' ? '· forecast' : '· historical'}
          </div>
          {BUILDING_TYPES.map(bt => (
            <div key={bt} style={{ display: 'flex', alignItems: 'center', gap: 6, marginTop: 2,
                                   opacity: activeBTs.includes(bt) ? 1 : 0.4 }}>
              <span style={{ width: 8, height: 8, background: BT_COLORS[bt], display: 'inline-block', borderRadius: 1 }} />
              <span style={{ flex: 1 }}>{bt}</span>
              <span style={{ fontVariantNumeric: 'tabular-nums' }}>
                {metric === 'value' ? '$' + fmtM(hover[bt]) : fmtInt(hover[bt])}
              </span>
            </div>
          ))}
          <div style={{ borderTop: '1px solid var(--rule)', marginTop: 6, paddingTop: 4,
                        display: 'flex', justifyContent: 'space-between', fontWeight: 700 }}>
            <span>Total (visible)</span>
            <span style={{ fontVariantNumeric: 'tabular-nums' }}>
              {metric === 'value' ? '$' + fmtM(hover._total) : fmtInt(hover._total)}
            </span>
          </div>
        </div>
      )}
    </div>
  );
}

/* ─────────────────────── Region row ─────────────────────── */
function RegionRow({ region, activeBTs, metric, shocks }) {
  const last2024 = region.historical[region.historical.length - 1];
  const horizonYr = region.forecasts_total.ensemble[region.forecasts_total.ensemble.length - 1].year;
  const ensembleEnd = region.forecasts_total.ensemble[region.forecasts_total.ensemble.length - 1];
  const delta = (ensembleEnd[metric] / last2024[metric] - 1) * 100;

  return (
    <div style={{ display: 'grid', gridTemplateColumns: '200px 1fr', gap: 24, padding: '20px 0', borderBottom: '1px solid var(--rule-2)' }}>
      <div>
        <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: '.12em', textTransform: 'uppercase', color: 'var(--ink-3)' }}>{region.short}</div>
        <div style={{ fontFamily: 'var(--serif)', fontSize: 17, color: 'var(--ink)', marginTop: 2, lineHeight: 1.2 }}>
          {region.name}
        </div>
        <div style={{ marginTop: 10, fontSize: 11, color: 'var(--ink-2)', fontVariantNumeric: 'tabular-nums', lineHeight: 1.7 }}>
          <div>2024 baseline: <b style={{ color: 'var(--ink)' }}>{metric === 'value' ? '$' + fmtM(last2024[metric]) : fmtInt(last2024[metric])}</b></div>
          <div>{horizonYr} ensemble: <b style={{ color: 'var(--ink)' }}>{metric === 'value' ? '$' + fmtM(ensembleEnd[metric]) : fmtInt(ensembleEnd[metric])}</b></div>
          <div style={{ color: delta >= 0 ? 'var(--good)' : 'var(--bad)', fontWeight: 600 }}>
            {fmtPct(delta)} over {horizonYr - 2024} yrs
          </div>
        </div>
      </div>
      <div>
        <StackedAreaChart historical={region.historical}
                          by_building_type={region.by_building_type}
                          activeBTs={activeBTs}
                          metric={metric}
                          shocks={shocks}
                          height={190} />
      </div>
    </div>
  );
}

/* ─────────────────────── Building-type legend ─────────────────────── */
function BuildingTypeLegend({ activeBTs, onToggle }) {
  return (
    <div style={{ display: 'flex', gap: 14, flexWrap: 'wrap' }}>
      {BUILDING_TYPES.map(bt => {
        const on = activeBTs.includes(bt);
        return (
          <button key={bt} onClick={() => onToggle(bt)}
                  title={on ? 'Hide ' + bt : 'Show ' + bt}
                  style={{
                    appearance: 'none', border: '1px solid var(--rule)', background: on ? 'var(--bg)' : 'var(--bg-alt)',
                    padding: '4px 10px', cursor: 'pointer',
                    display: 'inline-flex', alignItems: 'center', gap: 8,
                    opacity: on ? 1 : 0.45,
                    fontSize: 12, color: 'var(--ink)', borderRadius: 2,
                  }}>
            <span style={{ width: 12, height: 12, background: BT_COLORS[bt], borderRadius: 2,
                           border: on ? 'none' : '1px solid var(--rule)' }} />
            <span style={{ fontWeight: 500 }}>{bt}</span>
          </button>
        );
      })}
    </div>
  );
}

/* ─────────────────────── Shock editor row ─────────────────────── */
function ShockRow({ shock, onChange, onRemove, horizonYear }) {
  const meta = SHOCK_TYPES[shock.type] || SHOCK_TYPES.custom;
  const [open, setOpen] = useState(false);
  const update = (patch) => onChange({ ...shock, ...patch });

  const neg = shock.magnitude < 0;

  return (
    <div style={{ border: '1px solid var(--rule)', borderLeft: `3px solid ${neg ? 'var(--bad)' : 'var(--good)'}`,
                  borderRadius: 2, marginBottom: 8, background: 'var(--bg)' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '8px 10px', cursor: 'pointer' }}
           onClick={() => setOpen(o => !o)}>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--ink)' }}>{meta.label}</div>
          <div style={{ fontSize: 10, color: 'var(--ink-3)', fontFamily: 'var(--mono)',
                        fontVariantNumeric: 'tabular-nums' }}>
            {shock.year}{shock.duration > 1 ? `→${shock.year + shock.duration - 1}` : ''}
            {' · '}
            <span style={{ color: neg ? 'var(--bad)' : 'var(--good)', fontWeight: 700 }}>
              {shock.magnitude > 0 ? '+' : ''}{shock.magnitude}%
            </span>
          </div>
        </div>
        <button onClick={(e) => { e.stopPropagation(); onRemove(); }}
                style={{ appearance: 'none', border: 0, background: 'transparent', cursor: 'pointer',
                         color: 'var(--ink-3)', fontSize: 16, lineHeight: 1, padding: 4 }}
                title="Remove shock">×</button>
        <span style={{ color: 'var(--ink-3)', fontSize: 10, fontFamily: 'var(--mono)' }}>{open ? '▾' : '▸'}</span>
      </div>

      {open && (
        <div style={{ padding: '4px 10px 10px', borderTop: '1px solid var(--rule-2)' }}>
          <div style={{ fontSize: 10, color: 'var(--ink-3)', letterSpacing: '.08em',
                        textTransform: 'uppercase', marginTop: 6 }}>Type</div>
          <select value={shock.type} onChange={(e) => {
                    const t = e.target.value;
                    const def = SHOCK_TYPES[t]?.default || {};
                    update({ type: t, duration: def.duration ?? shock.duration, magnitude: def.magnitude ?? shock.magnitude });
                  }}
                  style={{ width: '100%', padding: '4px 6px', fontSize: 12,
                           border: '1px solid var(--rule)', borderRadius: 2,
                           background: 'var(--bg)', color: 'var(--ink)', marginTop: 2 }}>
            {Object.entries(SHOCK_TYPES).map(([k, v]) => (
              <option key={k} value={k}>{v.label}</option>
            ))}
          </select>

          <div style={{ marginTop: 8 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span style={{ fontSize: 10, color: 'var(--ink-3)', letterSpacing: '.08em', textTransform: 'uppercase' }}>Start year</span>
              <span style={{ fontFamily: 'var(--mono)', fontSize: 11, color: 'var(--ink)' }}>{shock.year}</span>
            </div>
            <input type="range" min={2025} max={horizonYear} step={1} value={shock.year}
                   onChange={(e) => update({ year: Number(e.target.value) })}
                   style={{ width: '100%', accentColor: 'var(--accent)' }} />
          </div>

          <div style={{ marginTop: 6 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span style={{ fontSize: 10, color: 'var(--ink-3)', letterSpacing: '.08em', textTransform: 'uppercase' }}>Duration (yrs)</span>
              <span style={{ fontFamily: 'var(--mono)', fontSize: 11, color: 'var(--ink)' }}>{shock.duration}</span>
            </div>
            <input type="range" min={1} max={10} step={1} value={shock.duration}
                   onChange={(e) => update({ duration: Number(e.target.value) })}
                   style={{ width: '100%', accentColor: 'var(--accent)' }} />
          </div>

          <div style={{ marginTop: 6 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span style={{ fontSize: 10, color: 'var(--ink-3)', letterSpacing: '.08em', textTransform: 'uppercase' }}>Magnitude (%)</span>
              <span style={{ fontFamily: 'var(--mono)', fontSize: 11,
                             color: neg ? 'var(--bad)' : 'var(--good)' }}>
                {shock.magnitude > 0 ? '+' : ''}{shock.magnitude}%
              </span>
            </div>
            <input type="range" min={-50} max={50} step={1} value={shock.magnitude}
                   onChange={(e) => update({ magnitude: Number(e.target.value) })}
                   style={{ width: '100%', accentColor: neg ? 'var(--bad)' : 'var(--good)' }} />
          </div>

          <div style={{ marginTop: 8, fontFamily: 'var(--serif)', fontStyle: 'italic',
                        fontSize: 11, color: 'var(--ink-3)', lineHeight: 1.4 }}>
            {meta.blurb}
          </div>
        </div>
      )}
    </div>
  );
}

/* ─────────────────────── Scenario left rail ─────────────────────── */
function ScenarioRail({ params, onChange, onShocksChange, onRun, status, scenarioId }) {
  const Section = ({ title, children }) => (
    <div style={{ padding: '14px 16px', borderBottom: '1px solid var(--rule-2)' }}>
      <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: '.12em', textTransform: 'uppercase',
                    color: 'var(--ink-3)', marginBottom: 8 }}>{title}</div>
      {children}
    </div>
  );

  const NumberSlider = ({ value, min, max, step, suffix, onCommit, fmt, accent }) => (
    <div>
      <div style={{ display: 'flex', alignItems: 'baseline', justifyContent: 'space-between' }}>
        <span style={{ fontFamily: 'var(--serif)', fontSize: 22, fontVariantNumeric: 'tabular-nums', color: 'var(--ink)' }}>
          {fmt ? fmt(value) : Number(value).toFixed(step < 1 ? 1 : 0)}{suffix}
        </span>
        <span style={{ fontSize: 10, color: 'var(--ink-3)', fontFamily: 'var(--mono)' }}>
          {min}{suffix} – {max}{suffix}
        </span>
      </div>
      <input type="range" min={min} max={max} step={step} value={value}
             onChange={(e) => onCommit(Number(e.target.value))}
             style={{ width: '100%', marginTop: 4, accentColor: accent || 'var(--accent)' }} />
    </div>
  );

  const fiscalLabel = (v) => {
    if (v <= -0.8) return 'Very conservative';
    if (v <= -0.3) return 'Conservative';
    if (v < 0.3)   return 'Neutral';
    if (v < 0.8)   return 'Liberal';
    return 'Very liberal';
  };

  const shocks = params.shocks || [];

  const addShock = () => {
    const def = SHOCK_TYPES.earthquake.default;
    onShocksChange([...shocks, {
      id: newId(),
      type: 'earthquake',
      year: Math.min(2030, params.horizon_year - 1),
      duration: def.duration,
      magnitude: def.magnitude,
    }]);
  };
  const updateShock = (idx, next) => {
    const out = shocks.slice();
    out[idx] = next;
    onShocksChange(out);
  };
  const removeShock = (idx) => {
    onShocksChange(shocks.filter((_, i) => i !== idx));
  };

  return (
    <aside style={{
      width: 260,
      flexShrink: 0,
      borderRight: '1px solid var(--rule)',
      background: 'var(--bg)',
      alignSelf: 'stretch',
      overflowY: 'auto',
    }}>
      <div style={{ padding: '16px 16px 8px', borderBottom: '1px solid var(--rule)' }}>
        <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: '.14em', textTransform: 'uppercase',
                      color: 'var(--accent)' }}>STAGE 1 · INPUTS</div>
        <div style={{ fontFamily: 'var(--serif)', fontSize: 18, marginTop: 2 }}>Scenario assumptions</div>
      </div>

      <Section title="GDP growth (annual)">
        <NumberSlider value={params.gdp_chg} min={-2} max={6} step={0.1} suffix="%"
                      onCommit={v => onChange('gdp_chg', v)} />
      </Section>
      <Section title="Population growth (annual)">
        <NumberSlider value={params.pop_chg} min={-1} max={4} step={0.1} suffix="%"
                      onCommit={v => onChange('pop_chg', v)} />
      </Section>
      <Section title="Inflation (annual)">
        <NumberSlider value={params.inflation} min={0} max={8} step={0.1} suffix="%"
                      onCommit={v => onChange('inflation', v)} />
      </Section>

      <Section title="Fiscal stance">
        <div>
          <div style={{ display: 'flex', alignItems: 'baseline', justifyContent: 'space-between' }}>
            <span style={{ fontFamily: 'var(--serif)', fontSize: 17, color: 'var(--ink)' }}>
              {fiscalLabel(params.fiscal)}
            </span>
            <span style={{ fontFamily: 'var(--mono)', fontSize: 11, color: 'var(--ink-3)',
                           fontVariantNumeric: 'tabular-nums' }}>
              {params.fiscal > 0 ? '+' : ''}{Number(params.fiscal).toFixed(2)}
            </span>
          </div>
          <input type="range" min={-1} max={1} step={0.05} value={params.fiscal}
                 onChange={(e) => onChange('fiscal', Number(e.target.value))}
                 style={{ width: '100%', marginTop: 4, accentColor: 'var(--accent)' }} />
          <div style={{ display: 'flex', justifyContent: 'space-between',
                        fontSize: 9, color: 'var(--ink-3)', fontFamily: 'var(--mono)',
                        letterSpacing: '.06em', marginTop: 2 }}>
            <span>VERY CONS. (-1)</span><span>VERY LIB. (+1)</span>
          </div>
        </div>
      </Section>

      <Section title="Horizon year">
        <NumberSlider value={params.horizon_year} min={2025} max={2050} step={1} suffix=""
                      onCommit={v => onChange('horizon_year', v)} />
      </Section>

      <Section title={`Shocks & stresses · ${shocks.length}`}>
        {shocks.length === 0 && (
          <div style={{ fontFamily: 'var(--serif)', fontStyle: 'italic', fontSize: 11.5,
                        color: 'var(--ink-3)', lineHeight: 1.4, marginBottom: 8 }}>
            No shocks. Add an event (earthquake, flood, pandemic…) to stress-test the forecast.
          </div>
        )}
        {shocks.map((sh, i) => (
          <ShockRow key={sh.id || i} shock={sh}
                    horizonYear={params.horizon_year}
                    onChange={(next) => updateShock(i, next)}
                    onRemove={() => removeShock(i)} />
        ))}
        <button onClick={addShock}
                style={{ width: '100%', appearance: 'none', border: '1px dashed var(--rule)',
                         background: 'var(--bg-alt)', padding: '8px',
                         fontSize: 11, fontWeight: 600, letterSpacing: '.08em',
                         textTransform: 'uppercase', color: 'var(--ink-2)',
                         cursor: 'pointer', borderRadius: 2 }}>
          + Add shock
        </button>
      </Section>

      <div style={{ padding: '16px' }}>
        <button className="btn" onClick={onRun} disabled={status === 'running'}
                style={{ width: '100%' }}>
          {status === 'running' ? '… running' : (scenarioId ? '↻ Re-run forecast' : '▶ Run forecast')}
        </button>
        {scenarioId && (
          <div style={{ marginTop: 10, fontSize: 10, color: 'var(--ink-3)',
                        fontFamily: 'var(--mono)', wordBreak: 'break-all' }}>
            <div style={{ letterSpacing: '.1em' }}>SCENARIO ID</div>
            <div style={{ color: 'var(--ink-2)' }}>{scenarioId}</div>
          </div>
        )}
      </div>
    </aside>
  );
}

/* ─────────────────────── Main Forecast component ─────────────────────── */
export function Forecast({ result, status, error, params, onRun, onSetParam, onSetShocks, onSeedSimulation }) {
  const [metric, setMetric] = useState('value');
  const [activeBTs, setActiveBTs] = useState(BUILDING_TYPES);

  const toggleBT = (bt) => {
    setActiveBTs(L => L.includes(bt) ? L.filter(x => x !== bt) : [...L, bt]);
  };

  const shocksForChart = result?.params?.shocks ?? params.shocks ?? [];

  return (
    <div style={{ display: 'flex', alignItems: 'stretch', margin: '0 -20px' }}>
      <ScenarioRail params={params}
                    onChange={onSetParam}
                    onShocksChange={onSetShocks}
                    onRun={onRun}
                    status={status}
                    scenarioId={result?.scenario_id} />

      <div style={{ flex: 1, minWidth: 0, padding: '20px 20px 40px' }}>
        {error && (
          <div style={{ padding: '12px 16px', background: 'var(--bg-alt)', border: '1px solid var(--rule)',
                        borderLeft: '3px solid var(--bad)', marginBottom: 20, fontSize: 12, fontFamily: 'var(--mono)' }}>
            <b style={{ color: 'var(--bad)' }}>Forecast failed</b> — {error}
          </div>
        )}

        {!result && status !== 'running' && (
          <div style={{ padding: '60px 20px', textAlign: 'center', color: 'var(--ink-3)',
                        border: '1px dashed var(--rule)', borderRadius: 2, background: 'var(--bg-alt)' }}>
            <div style={{ fontFamily: 'var(--serif)', fontStyle: 'italic', fontSize: 17, color: 'var(--ink-2)' }}>
              No forecast yet.
            </div>
            <div style={{ marginTop: 8, fontSize: 13 }}>
              Adjust scenario inputs on the left and click <b>Run forecast</b>.
            </div>
          </div>
        )}

        {status === 'running' && !result && (
          <div style={{ padding: '60px 20px', textAlign: 'center', color: 'var(--ink-3)',
                        fontFamily: 'var(--serif)', fontStyle: 'italic', fontSize: 17 }}>
            Running ensemble forecast…
          </div>
        )}

        {result && (
          <>
            <div className="panel" style={{ padding: 0, marginBottom: 24 }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                            padding: '14px 20px', borderBottom: '1px solid var(--rule)', gap: 16, flexWrap: 'wrap' }}>
                <div>
                  <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: '.12em', textTransform: 'uppercase',
                                color: 'var(--ink-3)' }}>FORECAST · BY REGION (ENSEMBLE)</div>
                  <div style={{ fontFamily: 'var(--serif)', fontSize: 18, marginTop: 2 }}>
                    Six regions, stacked by building type
                  </div>
                </div>
                <div style={{ display: 'flex', gap: 16, alignItems: 'center', flexWrap: 'wrap' }}>
                  <div className="filter-row" style={{ margin: 0 }}>
                    <div className="seg">
                      <button className={metric === 'value' ? 'active' : ''} onClick={() => setMetric('value')}>Value (NZD M)</button>
                      <button className={metric === 'count' ? 'active' : ''} onClick={() => setMetric('count')}>Project count</button>
                    </div>
                  </div>
                  <BuildingTypeLegend activeBTs={activeBTs} onToggle={toggleBT} />
                </div>
              </div>
              <div style={{ padding: '0 24px' }}>
                {result.regions.map(r => (
                  <RegionRow key={r.name} region={r} metric={metric}
                             activeBTs={activeBTs} shocks={shocksForChart} />
                ))}
              </div>
            </div>

            <div className="panel" style={{ padding: '18px 22px' }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 18, flexWrap: 'wrap' }}>
                <div style={{ maxWidth: '62ch' }}>
                  <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: '.12em', textTransform: 'uppercase', color: 'var(--accent)' }}>STAGE 2 · ALLOCATION</div>
                  <div style={{ fontFamily: 'var(--serif)', fontSize: 20, marginTop: 4 }}>Hand the ensemble forecast to the ABM simulator</div>
                  <p style={{ fontFamily: 'var(--serif)', fontStyle: 'italic', fontSize: 13.5, color: 'var(--ink-2)', margin: '6px 0 0', lineHeight: 1.5 }}>
                    Sends the scenario ID to the Python backend, which generates a project pipeline from the
                    ensemble path, runs the agent-based allocator, and posts the resulting
                    <span className="mono"> results.sqlite3</span> back here. While the backend is offline,
                    this just opens the upload dialog.
                  </p>
                </div>
                <button className="btn" onClick={onSeedSimulation} disabled={!result || status === 'running'}>
                  Run allocation simulation →
                </button>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
