/* loader.js — adapter from external stats.json / sqlite3 → internal `cur` shape used by the dashboard.
 *
 * External stats.json (single year) shape (from canconstruct_abm/stats.json):
 *   {
 *     year, total_projects, total_companies, projects_with_main,
 *     projects_fully_allocated, projects_partially_allocated, projects_unassigned,
 *     total_value, total_paw, total_value_allocated, total_value_unallocated,
 *     average_subs_per_allocated_project, companies_with_remaining_capacity,
 *     unassigned_projects: [...],
 *     // (other project arrays may be present — fully/partially allocated)
 *     // companies: [...]
 *     per_region_breakdown?: { [region]: { ... } },
 *     per_category_breakdown?: { [category]: { total, fully_allocated, partially_allocated, unassigned } },
 *   }
 *
 * Internal `cur` shape required by the dashboard:
 *   { year, params, projects[], companies[], stats: { ...flat keys + heatmap + band_utilisation } }
 */
import initSqlJs from 'sql.js/dist/sql-wasm.js';
import sqlWasmUrl from 'sql.js/dist/sql-wasm.wasm?url';
import {
  REGIONS, PROJECT_CATEGORIES, COMPANY_CATEGORIES, SIZE_BANDS_ORDER,
  inHousePct, reach as reachFn, sizeBand as sizeBandFn,
} from './data.js';

/** SQLite ``projects.allocation_status`` → dashboard internal status. */
export const SQLITE_PROJECT_ALLOCATION_STATUS = {
  F: 'fully_allocated',
  P: 'partial',
  N: 'unassigned',
};

export function sqliteProjectAllocationStatusToInternal(raw) {
  const k = raw == null ? '' : String(raw).trim();
  if (!k) return 'unassigned';
  const code = SQLITE_PROJECT_ALLOCATION_STATUS[k.toUpperCase()];
  if (code) return code;
  if (k === 'full') return 'fully_allocated';
  if (k === 'partial') return 'partial';
  if (k === 'none') return 'unassigned';
  return 'unassigned';
}

const COMPANY_SUFFIX = {
  E301: ['Homes','Residential','Builders'],
  E302: ['Construction','Commercial','Group'],
  E310: ['Civil','Infrastructure','Engineering'],
  E321: ['Earthworks','Site Services','Land Co'],
  E322: ['Structural','Steel & Frame','Foundations'],
  E323: ['Electrical','Mechanical','Services'],
  E324: ['Interiors','Finishings','Joinery'],
  E329: ['Trades','Specialists','Contracting'],
};
const NAME_STEMS = ['Kahu','Tui','Rata','Kowhai','Aoraki','Whenua','Hauraki','Manawa','Pounamu','Mahi','Wai','Ahi'];
const PROJECT_PREFIXES = {
  'Residential': ['Apartments','Townhomes','Housing','Subdivision'],
  'Commercial':  ['Office','Retail','Hotel','Mixed-use'],
  'Institutional':['School','Hospital','Library','University'],
  'Industrial': ['Warehouse','Plant','Distribution Centre','Factory'],
  'Transportation':['Highway','Bridge','Rail','Interchange'],
  'Utilities':   ['Wastewater','Power','Substation','Pipeline'],
  'Site development and earthworks':['Site Prep','Earthworks','Ground Improvement','Reclamation'],
};

function looksLikeProject(o) {
  return o && typeof o === 'object'
    && ('project_id' in o)
    && ('paw' in o || 'value' in o);
}
function looksLikeCompany(o) {
  return o && typeof o === 'object'
    && ('company_id' in o)
    && ('cac' in o || 'rac' in o);
}

function normaliseCompanyCategory(raw) {
  if (!raw) return null;
  const r = String(raw).trim();
  const byExactOrPrefix = COMPANY_CATEGORIES.find(
    c => c.name === r || c.name.startsWith(r + ' ') || r.startsWith(c.name),
  );
  if (byExactOrPrefix) return byExactOrPrefix;
  const code = r.match(/^(E\d{3})\b/)?.[1];
  if (code) {
    return COMPANY_CATEGORIES.find(c => c.name.startsWith(`${code} `)) || null;
  }
  return null;
}

function categorySuffixKey(canonicalName) {
  const t = (canonicalName || '').split(/\s+/)[0];
  return t || 'E301';
}

function regionBaseLabel(name) {
  return name.endsWith(' Region') ? name.slice(0, -' Region'.length) : name;
}

const LEGACY_REGION_KEYS = {
  'Rest of NI': 'Rest of North Island',
  'Rest of SI': 'Rest of South Island',
};

function normaliseRegion(raw) {
  if (!raw) return null;
  const s = String(raw).trim();
  const canon = LEGACY_REGION_KEYS[s] || s;
  return REGIONS.find(r => r.name === canon)
      || REGIONS.find(r => r.name === s)
      || REGIONS.find(r => regionBaseLabel(r.name) === canon)
      || REGIONS.find(r => regionBaseLabel(r.name) === s)
      || REGIONS.find(r => canon.startsWith(regionBaseLabel(r.name)))
      || REGIONS.find(r => s.startsWith(regionBaseLabel(r.name)));
}

/** Allocated / PAW — same basis as ProjectsTable `allocPct`. */
function allocatedFraction(p) {
  const paw = Number(p.paw) || 0;
  const main = Number(p.main_allocated) || 0;
  const subSum = Array.isArray(p.subcontractors)
    ? p.subcontractors.reduce((s, sc) => s + (Number(sc.allocated) || 0), 0)
    : 0;
  if (paw <= 0) return 1;
  return (main + subSum) / paw;
}

/** True when the project table Alloc column (fmtPct ×, 0) shows 100% or more. */
function allocationDisplaysFull(p) {
  const f = allocatedFraction(p);
  if (f >= 1) return true;
  return Number((f * 100).toFixed(0)) >= 100;
}

function reconcileProjectStatusForDisplay(p) {
  if (p.main_contractor_id == null) return p.status;
  if (p.status !== 'partial' && p.status !== 'stuck') return p.status;
  if (allocationDisplaysFull(p)) return 'fully_allocated';
  return p.status;
}

function classifyStatus(p) {
  if (p.main_contractor_id == null) return 'unassigned';
  if (allocationDisplaysFull(p)) return 'fully_allocated';
  return 'partial';
}

function synthCompanyName(seedNum, code) {
  const a = NAME_STEMS[seedNum % NAME_STEMS.length];
  const suff = COMPANY_SUFFIX[code] || ['Co'];
  const b = suff[Math.floor((seedNum / NAME_STEMS.length)) % suff.length];
  return `${a} ${b}`;
}
function synthProjectName(seedNum, cat, regionLabel) {
  const arr = PROJECT_PREFIXES[cat] || ['Project'];
  const pre = arr[seedNum % arr.length];
  return `${pre}, ${regionLabel}`;
}

function harvest(obj, out) {
  if (!obj) return;
  if (Array.isArray(obj)) {
    if (obj.length > 0) {
      const sample = obj[0];
      if (looksLikeProject(sample)) out.projects.push(obj);
      else if (looksLikeCompany(sample)) out.companies.push(obj);
    }
    for (const v of obj) {
      if (v && typeof v === 'object') harvest(v, out);
    }
    return;
  }
  if (typeof obj === 'object') {
    for (const k of Object.keys(obj)) {
      const v = obj[k];
      if (v && typeof v === 'object') harvest(v, out);
    }
  }
}

export function adaptStatsJson(raw) {
  if (!raw || typeof raw !== 'object') {
    throw new Error('Top-level JSON is not an object.');
  }
  const year = Number(raw.year) || new Date().getFullYear();

  const harvested = { projects: [], companies: [] };
  harvest(raw, harvested);
  const projMap = new Map();
  for (const arr of harvested.projects) {
    for (const p of arr) {
      if (!p || p.project_id == null) continue;
      const existing = projMap.get(p.project_id);
      if (!existing) projMap.set(p.project_id, p);
      else if (existing.main_contractor_id == null && p.main_contractor_id != null) projMap.set(p.project_id, p);
    }
  }
  const compMap = new Map();
  for (const arr of harvested.companies) {
    for (const c of arr) {
      if (!c || c.company_id == null) continue;
      if (!compMap.has(c.company_id)) compMap.set(c.company_id, c);
    }
  }
  if (projMap.size === 0 && compMap.size === 0) {
    throw new Error('No project or company entries detected in JSON.');
  }

  const projects = [];
  let pSeed = 0;
  for (const p of projMap.values()) {
    pSeed++;
    const region = normaliseRegion(p.region);
    const regionName = region ? region.name : (p.region || 'Auckland Region');
    const regionLabel = regionName;
    const cat = (PROJECT_CATEGORIES.includes(p.category) ? p.category : (p.category || 'Commercial'));
    const subs = Array.isArray(p.subcontractors) ? p.subcontractors : [];
    const main_alloc = Number(p.main_allocated) || 0;
    const subSum = subs.reduce((s, sc) => s + (Number(sc.allocated) || 0), 0);
    const paw = Number(p.paw) || (Number(p.value) || 0) / Math.max(1, Number(p.duration) || 1);
    const remaining = (p.remaining_workload != null)
      ? Number(p.remaining_workload)
      : Math.max(0, paw - main_alloc - subSum);
    const out = {
      project_id: p.project_id,
      name: p.name || synthProjectName(pSeed, cat, regionLabel),
      value: Number(p.value) || paw * (Number(p.duration) || 1),
      duration: Number(p.duration) || 1,
      paw,
      category: cat,
      region: regionName,
      main_contractor_id: p.main_contractor_id ?? null,
      main_allocated: main_alloc,
      remaining_workload: remaining,
      subcontractors: subs.map(sc => ({
        company_id: sc.company_id,
        allocated: Number(sc.allocated) || 0,
      })),
      status: null,
    };
    out.status = classifyStatus(out);
    projects.push(out);
  }

  const companies = [];
  let cSeed = 0;
  for (const c of compMap.values()) {
    cSeed++;
    const catEntry = normaliseCompanyCategory(c.category);
    const name  = catEntry ? catEntry.name : (c.category || 'E301 Residential Building Construction');
    const role  = catEntry ? catEntry.role : 'main';
    const suffixKey = catEntry ? categorySuffixKey(catEntry.name) : categorySuffixKey(name);
    const region = normaliseRegion(c.primary_region || c.region);
    const regionName = region ? region.name : (c.primary_region || c.region || 'Auckland Region');
    const cac         = Number(c.cac) || 0;
    const rac         = (c.rac != null) ? Number(c.rac) : cac;
    const initialCac  = c.initial_cac != null ? Number(c.initial_cac) : cac;
    const { initialTurnover, turnoverEnd } = resolveCompanyTurnover({
      ...c,
      initial_cac: initialCac,
      cac,
    });
    const ih          = inHousePct(initialTurnover);
    companies.push({
      company_id:      c.company_id,
      name:            c.name || synthCompanyName(cSeed, suffixKey),
      turnover:        turnoverEnd,
      cac, rac,
      initial_cac:     initialCac,
      initial_turnover: initialTurnover,
      in_house_pct:    ih,
      category:        name,
      role,
      region:          regionName,
      reach:           reachFn(initialTurnover),
      size_band:       sizeBandFn(initialTurnover),
      awarded_main:    [],
      awarded_sub:     [],
      _ext_main_awards: Number(c.main_awards) || 0,
      _ext_sub_awards:  Number(c.sub_awards) || 0,
    });
  }

  const byId = new Map(companies.map(c => [c.company_id, c]));
  for (const p of projects) {
    if (p.main_contractor_id != null) {
      const c = byId.get(p.main_contractor_id);
      if (c) c.awarded_main.push({ project_id: p.project_id, allocated: p.main_allocated });
    }
    for (const sc of p.subcontractors) {
      const c = byId.get(sc.company_id);
      if (c) c.awarded_sub.push({ project_id: p.project_id, allocated: sc.allocated });
    }
  }

  const stats = buildStats(year, raw, projects, companies);

  return {
    year,
    params: { source: 'uploaded', filename: raw.__filename || 'stats.json' },
    projects, companies, stats,
  };
}

function estimateTurnover(cac) {
  const bands = [
    { t: 200_000_000, ih: 0.10 },
    { t: 100_000_000, ih: 0.20 },
    { t:  50_000_000, ih: 0.20 },
    { t:  20_000_000, ih: 0.30 },
    { t:  10_000_000, ih: 0.30 },
    { t:   5_000_000, ih: 0.40 },
    { t:   1_000_000, ih: 0.50 },
    { t:     100_000, ih: 0.60 },
    { t:           0, ih: 1.00 },
  ];
  for (const b of bands) {
    if (cac >= b.t / b.ih) return Math.max(b.t, cac * b.ih);
  }
  return cac;
}

/** Start-of-year and end-of-year turnover (revenue) for dashboard utilisation. */
function resolveCompanyTurnover(c) {
  const initialCac = c.initial_cac != null ? Number(c.initial_cac) : Number(c.cac) || 0;
  const initialTurnover =
    c.initial_turnover != null && Number.isFinite(Number(c.initial_turnover))
      ? Number(c.initial_turnover)
      : estimateTurnover(initialCac);
  const endRaw = c.turnover;
  const turnoverEnd =
    endRaw != null && Number.isFinite(Number(endRaw)) ? Number(endRaw) : initialTurnover;
  return { initialTurnover, turnoverEnd };
}

function buildStats(year, raw, projects, companies) {
  const N = projects.length;
  const withMain = projects.filter(p => p.main_contractor_id != null);
  const fully    = projects.filter(p => p.status === 'fully_allocated');
  const partial  = projects.filter(p => p.status === 'partial' || p.status === 'stuck');
  const unassigned = projects.filter(p => p.main_contractor_id == null);

  const totalValue = projects.reduce((s, p) => s + p.value, 0);
  const totalPaw   = projects.reduce((s, p) => s + p.paw, 0);
  const allocated  = projects.reduce((s, p) =>
    s + p.main_allocated + p.subcontractors.reduce((q, sc) => q + sc.allocated, 0), 0);
  const unalloc    = totalPaw - allocated;
  const subsCount  = withMain.reduce((s, p) => s + p.subcontractors.length, 0);

  const heat = {};
  for (const r of REGIONS) heat[r.name] = {};
  for (const r of REGIONS) for (const c of PROJECT_CATEGORIES) heat[r.name][c] = 0;
  for (const p of projects) {
    if (p.status !== 'fully_allocated' && heat[p.region] && heat[p.region][p.category] != null) {
      heat[p.region][p.category] += (p.main_contractor_id == null ? p.paw : p.remaining_workload);
    }
  }

  const bandUtil = {};
  for (const b of SIZE_BANDS_ORDER) {
    bandUtil[b] = { used: 0, turnover_start: 0, count: 0, withCap: 0 };
  }
  for (const c of companies) {
    const b = bandUtil[c.size_band] || (bandUtil[c.size_band] = { used:0, turnover_start:0, count:0, withCap:0 });
    const t0 = Number(c.initial_turnover) || 0;
    const t1 = Number(c.turnover) || 0;
    b.used += t0 - t1;
    b.turnover_start += t0;
    b.count++;
    if (t1 > 1) b.withCap++;
  }

  const pick = (k, fallback) => (raw && Number.isFinite(raw[k])) ? raw[k] : fallback;

  return {
    year,
    total_projects: pick('total_projects', N),
    total_companies: pick('total_companies', companies.length),
    projects_with_main: pick('projects_with_main', withMain.length),
    projects_fully_allocated: pick('projects_fully_allocated', fully.length),
    projects_partially_allocated: pick('projects_partially_allocated', partial.length),
    projects_unassigned: pick('projects_unassigned', unassigned.length),
    total_value: pick('total_value', totalValue),
    total_paw: pick('total_paw', totalPaw),
    total_value_allocated: pick('total_value_allocated', allocated),
    total_value_unallocated: pick('total_value_unallocated', unalloc),
    average_subs_per_allocated_project: pick('average_subs_per_allocated_project',
      withMain.length ? subsCount / withMain.length : 0),
    companies_with_remaining_capacity: pick('companies_with_remaining_capacity',
      companies.filter(c => (Number(c.turnover) || 0) > 1).length),
    heatmap: heat,
    band_utilisation: bandUtil,
    per_region_breakdown: (function () {
      if (!raw || !raw.per_region_breakdown) return null;
      const out = {};
      for (const [k, v] of Object.entries(raw.per_region_breakdown)) {
        const r = normaliseRegion(k);
        out[r ? r.name : k] = v;
      }
      return out;
    }()),
  };
}

export async function readJsonFile(file) {
  const text = await file.text();
  let json;
  try { json = JSON.parse(text); }
  catch (e) { throw new Error(`File is not valid JSON: ${e.message}`); }
  if (json && typeof json === 'object' && !Array.isArray(json)) {
    json.__filename = file.name;
  }
  return json;
}

// ── SQLite results DB adapter ─────────────────────────────────────────────

function _sqlRows(result) {
  if (!result || result.length === 0) return [];
  const { columns, values } = result[0];
  return values.map(row => Object.fromEntries(columns.map((c, i) => [c, row[i]])));
}

function adaptSqliteDb(db, filename) {
  const runMeta = _sqlRows(db.exec(
    'SELECT MAX(id) AS run_id, year FROM simulation_runs GROUP BY year ORDER BY year'
  ));
  if (runMeta.length === 0) throw new Error('No simulation runs found in this database.');

  const result = {};

  for (const { run_id, year } of runMeta) {
    const runRow = _sqlRows(db.exec(
      `SELECT * FROM simulation_runs WHERE id = ${run_id}`
    ))[0];

    const projRows = _sqlRows(db.exec(
      `SELECT * FROM projects WHERE run_id = ${run_id}`
    ));
    const subRows = _sqlRows(db.exec(
      `SELECT * FROM project_subs WHERE run_id = ${run_id}`
    ));
    const compRows = _sqlRows(db.exec(
      `SELECT * FROM companies WHERE run_id = ${run_id}`
    ));
    const regionRows = _sqlRows(db.exec(
      `SELECT * FROM region_breakdown WHERE run_id = ${run_id}`
    ));
    const catRows = _sqlRows(db.exec(
      `SELECT * FROM category_breakdown WHERE run_id = ${run_id}`
    ));

    const subsMap = new Map();
    for (const s of subRows) {
      if (!subsMap.has(s.project_id)) subsMap.set(s.project_id, []);
      subsMap.get(s.project_id).push({ company_id: s.company_id, allocated: s.amount });
    }

    const projects = [];
    let pSeed = 0;
    for (const p of projRows) {
      pSeed++;
      const region   = normaliseRegion(p.region);
      const regionName  = region ? region.name  : (p.region  || 'Auckland Region');
      const regionLabel = regionName;
      const subs   = subsMap.get(p.project_id) || [];
      const status = sqliteProjectAllocationStatusToInternal(p.allocation_status);
      const persistedName = p.name != null && String(p.name).trim() !== ''
        ? String(p.name).trim()
        : null;
      const proj = {
        project_id:        p.project_id,
        name:              persistedName ?? synthProjectName(pSeed, p.category, regionLabel),
        value:             p.value,
        duration:          p.duration,
        paw:               p.paw,
        category:          p.category,
        region:            regionName,
        main_contractor_id: p.main_contractor_id,
        main_allocated:    p.main_allocated,
        remaining_workload: p.remaining_workload,
        subcontractors:    subs,
        status,
      };
      proj.status = reconcileProjectStatusForDisplay(proj);
      projects.push(proj);
    }

    const companies = [];
    let cSeed = 0;
    for (const c of compRows) {
      cSeed++;
      const catEntry   = normaliseCompanyCategory(c.category);
      const name       = catEntry ? catEntry.name : (c.category || 'E301 Residential Building Construction');
      const role       = catEntry ? catEntry.role : 'main';
      const suffixKey  = catEntry ? categorySuffixKey(catEntry.name) : categorySuffixKey(name);
      const region     = normaliseRegion(c.primary_region);
      const regionName = region ? region.name : (c.primary_region || 'Auckland Region');
      const cac            = Number(c.cac) || 0;
      const rac            = Number(c.rac);
      const initialCac     = c.initial_cac != null ? Number(c.initial_cac) : cac;
      const { initialTurnover, turnoverEnd } = resolveCompanyTurnover({
        ...c,
        initial_cac: initialCac,
        cac,
      });
      const ih             = inHousePct(initialTurnover);
      const companyPersistedName = c.name != null && String(c.name).trim() !== ''
        ? String(c.name).trim()
        : null;
      companies.push({
        company_id:      c.company_id,
        name:            companyPersistedName ?? synthCompanyName(cSeed, suffixKey),
        turnover:        turnoverEnd,
        cac, rac,
        initial_cac:     initialCac,
        initial_turnover: initialTurnover,
        in_house_pct:    ih,
        category:        name,
        role,
        region:          regionName,
        reach:           reachFn(initialTurnover),
        size_band:       sizeBandFn(initialTurnover),
        awarded_main:    [],
        awarded_sub:     [],
        _ext_main_awards: c.main_awards,
        _ext_sub_awards:  c.sub_awards,
      });
    }

    const byId = new Map(companies.map(c => [c.company_id, c]));
    for (const p of projects) {
      if (p.main_contractor_id != null) {
        const co = byId.get(p.main_contractor_id);
        if (co) co.awarded_main.push({ project_id: p.project_id, allocated: p.main_allocated });
      }
      for (const sc of p.subcontractors) {
        const co = byId.get(sc.company_id);
        if (co) co.awarded_sub.push({ project_id: p.project_id, allocated: sc.allocated });
      }
    }

    const per_region_breakdown = {};
    for (const r of regionRows) {
      const reg = normaliseRegion(r.region);
      per_region_breakdown[reg ? reg.name : r.region] = {
        total: r.total,
        fully_allocated: r.fully_allocated,
        partially_allocated: r.partially_allocated,
        unassigned: r.unassigned,
      };
    }

    const per_category_breakdown = {};
    for (const c of catRows) {
      per_category_breakdown[c.category] = {
        total: c.total,
        fully_allocated: c.fully_allocated,
        partially_allocated: c.partially_allocated,
        unassigned: c.unassigned,
      };
    }

    const rawForStats = {
      ...runRow,
      per_region_breakdown:   Object.keys(per_region_breakdown).length  ? per_region_breakdown  : null,
      per_category_breakdown: Object.keys(per_category_breakdown).length ? per_category_breakdown : null,
    };
    const stats = buildStats(year, rawForStats, projects, companies);

    result[year] = {
      year,
      params: { source: 'sqlite', filename: filename || 'results.sqlite3' },
      projects, companies, stats,
    };
  }

  return result;
}

export async function readSqliteFile(file) {
  const SQL = await initSqlJs({
    locateFile: () => sqlWasmUrl,
  });
  const buf = await file.arrayBuffer();
  const db  = new SQL.Database(new Uint8Array(buf));
  try {
    return adaptSqliteDb(db, file.name);
  } finally {
    db.close();
  }
}

export const ABM_LOADER = { adaptStatsJson, readJsonFile, readSqliteFile };
