// Interactive bidding-flow diagram (React Flow) — matches the architecture
// diagram in src/bidding.md. Click any node to see its explanation in a side
// drawer.

import React, { useState, useCallback } from 'react';
import ReactFlow, {
  Background,
  Controls,
  Handle,
  Position,
  MarkerType,
} from 'reactflow';
import 'reactflow/dist/style.css';

// ── Custom node shapes ──────────────────────────────────────────────────────

function BoxNode({ data }) {
  return (
    <div style={{
      background: '#f5f1e6',
      border: '1px solid #8a8478',
      borderRadius: 6,
      padding: '10px 14px',
      minWidth: 150,
      maxWidth: 200,
      textAlign: 'center',
      fontFamily: 'var(--sans)',
      fontSize: 12,
      color: '#1a1814',
      boxShadow: '0 1px 2px rgba(0,0,0,0.06)',
      cursor: 'pointer',
    }}>
      <Handle type="target" position={Position.Top} style={{ opacity: 0 }} />
      <Handle type="target" position={Position.Left} style={{ opacity: 0 }} id="l" />
      {data.label}
      <Handle type="source" position={Position.Bottom} style={{ opacity: 0 }} />
      <Handle type="source" position={Position.Right} style={{ opacity: 0 }} id="r" />
    </div>
  );
}

function DiamondNode({ data }) {
  // CSS-rotated square: nest the label so it stays upright.
  const size = 96;
  return (
    <div style={{
      width: size,
      height: size,
      position: 'relative',
      cursor: 'pointer',
    }}>
      <Handle type="target" position={Position.Top} style={{ opacity: 0 }} />
      <Handle type="target" position={Position.Left} style={{ opacity: 0 }} id="l" />
      <div style={{
        position: 'absolute',
        inset: 0,
        background: '#dbeafe',
        border: '1px solid #7da7d9',
        transform: 'rotate(45deg)',
        boxShadow: '0 1px 2px rgba(0,0,0,0.06)',
      }} />
      <div style={{
        position: 'absolute',
        inset: 0,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        fontFamily: 'var(--sans)',
        fontSize: 10.5,
        textAlign: 'center',
        padding: 8,
        color: '#1a1814',
        lineHeight: 1.15,
      }}>
        {data.label}
      </div>
      <Handle type="source" position={Position.Bottom} style={{ opacity: 0 }} />
      <Handle type="source" position={Position.Right} style={{ opacity: 0 }} id="r" />
    </div>
  );
}

function PoolNode({ data }) {
  return (
    <div style={{
      background: '#d6ead4',
      border: '1px solid #6b9a66',
      borderRadius: 999,
      padding: '12px 22px',
      minWidth: 170,
      maxWidth: 220,
      textAlign: 'center',
      fontFamily: 'var(--sans)',
      fontSize: 12,
      fontWeight: 500,
      color: '#1a1814',
      boxShadow: '0 1px 2px rgba(0,0,0,0.06)',
      cursor: 'pointer',
    }}>
      <Handle type="target" position={Position.Top} style={{ opacity: 0 }} />
      <Handle type="target" position={Position.Left} style={{ opacity: 0 }} id="l" />
      {data.label}
      <Handle type="source" position={Position.Bottom} style={{ opacity: 0 }} />
      <Handle type="source" position={Position.Right} style={{ opacity: 0 }} id="r" />
    </div>
  );
}

function TitleNode({ data }) {
  return (
    <div style={{
      background: '#faf8f3',
      border: '1px solid #1a1814',
      borderRadius: 999,
      padding: '12px 28px',
      minWidth: 220,
      textAlign: 'center',
      fontFamily: 'var(--serif)',
      fontSize: 14,
      fontWeight: 500,
      color: '#1a1814',
      cursor: 'pointer',
    }}>
      <Handle type="target" position={Position.Top} style={{ opacity: 0 }} />
      <Handle type="target" position={Position.Left} style={{ opacity: 0 }} id="l" />
      {data.label}
      <Handle type="source" position={Position.Bottom} style={{ opacity: 0 }} />
      <Handle type="source" position={Position.Right} style={{ opacity: 0 }} id="r" />
    </div>
  );
}

const nodeTypes = {
  box: BoxNode,
  diamond: DiamondNode,
  pool: PoolNode,
  title: TitleNode,
};

