// ── Edges ───────────────────────────────────────────────────────────────────

const E = (source, target, label, opts = {}) => ({
  id: `${source}-${target}`,
  source,
  target,
  label,
  type: 'smoothstep',
  markerEnd: { type: MarkerType.ArrowClosed, width: 14, height: 14, color: '#5a574e' },
  labelStyle: { fontSize: 10, fontFamily: 'var(--sans)', fill: '#4a463d', fontWeight: 500 },
  labelBgPadding: [4, 2],
  labelBgStyle: { fill: '#faf8f3', fillOpacity: 0.9 },
  style: { stroke: '#5a574e', strokeWidth: 1.2 },
  ...opts,
});

const edges = [
  // Title fans out to inputs
  { ...E('title', 'ssp_root', 'inputs') },
  { ...E('title', 'pf_root', 'inputs') },

  // Left input chain
  E('ssp_root', 'ssp_create'),
  E('ssp_create', 'ssp_capvars'),
  E('ssp_capvars', 'ssp_sort'),
  E('ssp_sort', 'ssp_calc_rac'),
  E('ssp_calc_rac', 'contractor_pool'),

  // Right input chain
  E('pf_root', 'pf_init'),
  E('pf_init', 'pf_generate'),
  E('pf_generate', 'pf_duration'),
  E('pf_duration', 'pf_paw'),
  E('pf_paw', 'pf_sort'),
  E('pf_sort', 'pf_append'),
  E('pf_append', 'pf_loop'),
  E('pf_loop', 'pf_inc', 'no'),
  E('pf_inc', 'pf_generate'),
  E('pf_loop', 'project_pool', 'yes'),

  // Pools feed main allocation loop
  E('contractor_pool', 'm_pick_c'),
  E('project_pool', 'm_pick_p'),

  // Main allocation eligibility chain
  E('m_pick_c', 'm_cat'),
  E('m_pick_p', 'm_cat'),
  E('m_cat', 'm_oa', 'YES'),
  E('m_oa', 'm_cac', 'YES'),
  E('m_cac', 'm_rac', 'YES'),
  E('m_rac', 'm_select', 'YES'),

  // Failure paths -> next contractor
  E('m_cat', 'm_next_c', 'NO'),
  E('m_oa', 'm_next_c', 'NO'),
  E('m_cac', 'm_next_c', 'NO'),
  E('m_rac', 'm_next_c', 'NO'),
  E('m_next_c', 'm_pick_c'),

  // Award flow
  E('m_select', 'm_set_value', 'award'),
  E('m_set_value', 'm_allocate_ih', 'split'),
  E('m_allocate_ih', 'm_update_wl', 'update'),
  E('m_update_wl', 'm_remove_p'),
  E('m_remove_p', 'm_no_main_pool'),
  E('m_remove_p', 'm_all_done'),

  // Outer guard
  E('m_all_done', 'm_pick_p', 'no'),
  E('m_all_done', 's_pick_p', 'yes'),
  E('m_no_main_pool', 'output'),

  // Subcontractor loop
  E('contractor_pool', 's_pick_c'),
  E('s_pick_c', 's_cat'),
  E('s_pick_p', 's_cat'),
  E('s_cat', 's_region', 'YES'),
  E('s_region', 's_rac', 'YES'),
  E('s_rac', 's_remainder', 'YES'),
  E('s_cat', 's_next_c', 'NO'),
  E('s_region', 's_next_c', 'NO'),
  E('s_rac', 's_next_c', 'NO'),
  E('s_next_c', 's_pick_c'),
  E('s_remainder', 's_create_pkg', 'YES'),
  E('s_create_pkg', 's_search', 'search'),
  E('s_search', 's_allocate', 'allocate'),
  E('s_allocate', 's_update_wl'),
  E('s_update_wl', 's_pick_c'),
  E('s_remainder', 's_mark_full', 'NO'),
  E('s_mark_full', 's_remove_full'),
  E('s_remove_full', 's_partial_pool'),
  E('s_partial_pool', 'output'),
];

// ── Component ───────────────────────────────────────────────────────────────

export function MethodologyDiagram() {
  const [selected, setSelected] = useState(null);

  const onNodeClick = useCallback((_, node) => {
    setSelected(node);
  }, []);

  return (
    <div style={{ position: 'relative', height: 720, background: '#faf8f3' }}>
      <ReactFlow
        nodes={nodes}
        edges={edges}
        nodeTypes={nodeTypes}
        onNodeClick={onNodeClick}
        nodesDraggable={false}
        nodesConnectable={false}
        elementsSelectable
        fitView
        fitViewOptions={{ padding: 0.06 }}
        proOptions={{ hideAttribution: true }}
        minZoom={0.2}
        maxZoom={2}
      >
        <Background color="#d9d3c4" gap={20} size={1} />
        <Controls showInteractive={false} />
      </ReactFlow>

      {selected && (
        <aside style={{
          position: 'absolute',
          top: 0,
          right: 0,
          bottom: 0,
          width: 360,
          background: '#fffefb',
          borderLeft: '1px solid #d9d3c4',
          padding: '20px 22px',
          boxShadow: '-12px 0 28px rgba(28,24,18,0.06)',
          overflowY: 'auto',
          zIndex: 10,
        }}>
          <button
            onClick={() => setSelected(null)}
            aria-label="Close"
            style={{
              position: 'absolute', top: 14, right: 14,
              border: 0, background: 'transparent',
              fontSize: 18, color: '#8a8478', cursor: 'pointer',
              padding: 4, lineHeight: 1,
            }}>
            ×
          </button>
          <div style={{
            fontSize: 10,
            color: '#8a8478',
            letterSpacing: '.12em',
            textTransform: 'uppercase',
            marginBottom: 6,
            fontWeight: 600,
          }}>
            {selected.type === 'diamond' ? 'Decision'
              : selected.type === 'pool' ? 'Output collection'
              : selected.type === 'title' ? 'Boundary'
              : 'Process step'}
          </div>
          <h4 style={{
            fontFamily: 'var(--serif)',
            fontSize: 18,
            fontWeight: 500,
            margin: '0 0 12px',
            paddingRight: 24,
            color: '#1a1814',
          }}>
            {selected.data.label}
          </h4>
          <p style={{
            fontSize: 13,
            lineHeight: 1.6,
            color: '#4a463d',
            margin: 0,
          }}>
            {selected.data.description}
          </p>
        </aside>
      )}
    </div>
  );
}
