import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Overview } from './overview.jsx';
import { Heatmap, ProjectDrawer, CompanyDrawer } from './screens.jsx';
import { ProjectsTable, CompaniesTable } from './tables.jsx';
import {
  useTweaks, TweaksPanel, TweakSection, TweakToggle, TweakRadio, TweakSelect,
} from './tweaks-panel.jsx';
import { ABM_LOADER } from './loader.js';
import { ABM } from './data.js';
import { fmt } from './utils.js';
import { Methodology } from './methodology.jsx';
import { ForecastAPI } from './forecast-api.js';
import { Forecast } from './forecast.jsx';
import { ForecastMethodology } from './forecast-methodology.jsx';

// Toggle for the "Forecast method" / "Allocation method" nav buttons.
// Controlled by VITE_SHOW_METHOD_TABS in .env.development (local) and
// .env.production (CI build). Defaults to false when unset.
const SHOW_METHOD_TABS = import.meta.env.VITE_SHOW_METHOD_TABS === 'true';

const TWEAK_DEFAULTS = /*EDITMODE-BEGIN*/{
  "dark": false,
  "density": "regular",
  "showUnassigned": true,
  "regionFilter": "all",
  "gdp_chg": 2.0,
  "pop_chg": 1.2,
  "inflation": 2.5,
  "fiscal": 0,
  "horizon_year": 2035,
  "shocks": []
}/*EDITMODE-END*/;

// Compact, nav-inline year picker
function NavYearPicker({ years, value, onChange }) {
  const [open, setOpen] = useState(false);
  const [text, setText] = useState(String(value));
  const ref = useRef(null);
  useEffect(() => { setText(String(value)); }, [value]);
  useEffect(() => {
    const onDoc = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener('mousedown', onDoc);
    return () => document.removeEventListener('mousedown', onDoc);
  }, []);
  const commit = () => {
    const n = parseInt(text, 10);
    if (Number.isFinite(n) && n >= 1900 && n <= 2200) onChange(n);
    else setText(String(value));
    setOpen(false);
  };
  const n = parseInt(text, 10);
  const known = years.includes(n);
  const filtered = years.filter(y => !text || String(y).startsWith(text));
  return (
    <div ref={ref} className="nav-yp" style={{ position:'relative', display:'flex', alignItems:'center', gap:6 }}>
      <button className="nav-yp-step" aria-label="Previous year"
              onClick={() => onChange(value - 1)}>‹</button>
      <div style={{ position:'relative' }}>
        <input
          type="text"
          inputMode="numeric"
          value={text}
          onFocus={() => setOpen(true)}
          onChange={e => { setText(e.target.value.replace(/[^0-9]/g,'').slice(0,4)); setOpen(true); }}
          onKeyDown={e => {
            if (e.key === 'Enter') commit();
            else if (e.key === 'Escape') { setText(String(value)); setOpen(false); }
            else if (e.key === 'ArrowUp')   { e.preventDefault(); onChange(value + 1); }
            else if (e.key === 'ArrowDown') { e.preventDefault(); onChange(value - 1); }
          }}
          onBlur={commit}
          onClick={() => setOpen(true)}
          className="nav-yp-input"
        />
        <span className="nav-yp-caret">▾</span>
        {open && (
          <div className="nav-yp-pop">
            <div className="nav-yp-pop-hd">Cached years</div>
            {filtered.map(y => (
              <div key={y}
                   onMouseDown={(e) => { e.preventDefault(); onChange(y); setText(String(y)); setOpen(false); }}
                   className={"nav-yp-row" + (y === value ? ' active' : '')}>
                <span>{y}</span>
                {y === value && <span className="nav-yp-tick">●</span>}
              </div>
            ))}
            {filtered.length === 0 && (
              <div className="nav-yp-empty">No matches</div>
            )}
            {Number.isFinite(n) && n >= 1900 && n <= 2200 && !known && (
              <div onMouseDown={(e) => { e.preventDefault(); onChange(n); setText(String(n)); setOpen(false); }}
                   className="nav-yp-gen">
                Generate {n} →
              </div>
            )}
          </div>
        )}
      </div>
      <button className="nav-yp-step" aria-label="Next year"
              onClick={() => onChange(value + 1)}>›</button>
    </div>
  );
}

export function App() {
  const [t, setTweak] = useTweaks(TWEAK_DEFAULTS);
  const [tab, setTab] = useState('forecast');
  const [run, setRun] = useState(null);
  const [year, setYear] = useState(null);
  const [selectedProject, setSelectedProject] = useState(null);
  const [selectedCompany, setSelectedCompany] = useState(null);
  const [uploadedMeta, setUploadedMeta] = useState(null);
  const [uploadError, setUploadError] = useState(null);
  const fileInputRef = useRef(null);

  // Forecast state
  const [forecastResult, setForecastResult] = useState(null);
  const [forecastStatus, setForecastStatus] = useState('idle');
  const [forecastError, setForecastError] = useState(null);

  const scenarioParams = {
    gdp_chg:      Number(t.gdp_chg ?? 2.0),
    pop_chg:      Number(t.pop_chg ?? 1.2),
    inflation:    Number(t.inflation ?? 2.5),
    fiscal:       typeof t.fiscal === 'number' ? t.fiscal : 0,
    horizon_year: Number(t.horizon_year ?? 2035),
    shocks:       Array.isArray(t.shocks) ? t.shocks : [],
  };

  const runForecast = useCallback(async () => {
    setForecastStatus('running');
    setForecastError(null);
    try {
      const res = await ForecastAPI.runForecast(scenarioParams);
      setForecastResult(res);
      setForecastStatus('done');
    } catch (e) {
      setForecastError(e.message || String(e));
      setForecastStatus('idle');
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [scenarioParams.gdp_chg, scenarioParams.pop_chg, scenarioParams.inflation, scenarioParams.fiscal, scenarioParams.horizon_year, JSON.stringify(scenarioParams.shocks)]);

  const handleUpload = useCallback(async (file) => {
    if (!file) return;
    setUploadError(null);
    try {
      let newRun;
      const isSqlite = /\.(sqlite3?|db)$/i.test(file.name);
      if (isSqlite) {
        newRun = await ABM_LOADER.readSqliteFile(file);
      } else {
        const raw = await ABM_LOADER.readJsonFile(file);
        const cur = ABM_LOADER.adaptStatsJson(raw);
        newRun = { [cur.year]: cur };
      }
      const yrs = Object.keys(newRun).map(Number).sort((a, b) => a - b);
      const firstCur = newRun[yrs[0]];
      setRun(newRun);
      setYear(yrs[0]);
      setUploadedMeta({
        filename: file.name,
        years: yrs,
        projects: firstCur.stats.total_projects,
        companies: firstCur.stats.total_companies,
      });
    } catch (e) {
      console.error(e);
      setUploadError(e.message || String(e));
    }
  }, []);

  useEffect(() => {
    document.documentElement.dataset.theme = t.dark ? 'dark' : 'light';
    document.documentElement.dataset.density = t.density;
  }, [t.dark, t.density]);

  const autoRanForecastRef = useRef(false);
  useEffect(() => {
    if (autoRanForecastRef.current) return;
    autoRanForecastRef.current = true;
    runForecast();
  }, [runForecast]);

  const years = run ? Object.keys(run).map(Number).sort((a,b)=>a-b) : [];
  const regionFilter = (t.regionFilter && t.regionFilter !== 'all') ? t.regionFilter : null;
  const setRegionFilter = (name) => setTweak('regionFilter', name || 'all');

  const cur = run && run[year];

  return (
    <div className="app">
      <header className="masthead" style={{ paddingTop: 14, paddingBottom: 10 }}>
        <div className="masthead-left">
          <span className="eyebrow">CanConstruct · Agent-Based Allocation Model</span>
        </div>
        <div className="masthead-right">
          <div>
            <div style={{ color: 'var(--ink-3)', fontSize: 10, letterSpacing: '.1em', textTransform:'uppercase' }}>Year in view</div>
            <div><b>{year ?? '—'}</b></div>
          </div>
          {uploadedMeta && (
            <div>
              <div style={{ color: 'var(--ink-3)', fontSize: 10, letterSpacing: '.1em', textTransform:'uppercase' }}>Source</div>
              <div><b style={{ fontFamily:'var(--mono)', fontSize:11 }}>{uploadedMeta.filename}</b></div>
            </div>
          )}
          <div style={{ display:'flex', gap:6, alignItems:'center' }}>
            <input type="file" accept=".sqlite3,.db,.json,application/json" ref={fileInputRef}
                   style={{ display:'none' }}
                   onChange={(e) => { const f = e.target.files?.[0]; e.target.value = ''; handleUpload(f); }} />
            <button className="btn ghost" style={{ padding:'5px 10px', fontSize:11, whiteSpace:'nowrap' }}
                    onClick={() => fileInputRef.current?.click()}
                    title="Load a results.sqlite3 produced by the simulation backend">
              ↑ Upload results DB
            </button>
          </div>
        </div>
      </header>

      <nav className="nav">
        {[
          ['forecast', 'Forecast'],
        ].map(([k, label]) => (
          <button key={k} className={tab === k ? 'active' : ''} onClick={()=>setTab(k)}>{label}</button>
        ))}
        <span style={{ alignSelf:'center', width:1, height:14, background:'var(--rule)', marginLeft:6, marginRight:6 }} />
        {[
          ['overview', 'Overview'],
          ['heatmap', 'Bottlenecks'],
          ['projects', 'Projects'],
          ['companies', 'Companies'],
        ].map(([k, label]) => (
          <button key={k} className={tab === k ? 'active' : ''} onClick={()=>setTab(k)}>{label}</button>
        ))}
        {SHOW_METHOD_TABS && (
          <>
            <span style={{ alignSelf:'center', width:1, height:14, background:'var(--rule)', marginLeft:6, marginRight:6 }} />
            {[
              ['forecast_method', 'Forecast method'],
              ['methodology', 'Allocation method'],
            ].map(([k, label]) => (
              <button key={k} className={tab === k ? 'active' : ''} onClick={()=>setTab(k)}>{label}</button>
            ))}
          </>
        )}
        <span className="nav-spacer" />
        {years.length > 0 && (
          <div className="nav-year">
            <span className="nav-year-label">Year</span>
            <NavYearPicker years={years} value={year} onChange={(y) => {
              const n = Number(y);
              if (!Number.isFinite(n) || !run[n]) return;
              setYear(n);
            }} />
          </div>
        )}
        <span className="nav-meta">
          {cur && <>
            <span><span className="dot good" />{fmt.fmtNum(cur.stats.projects_fully_allocated)} full</span>
            <span><span className="dot warn" />{fmt.fmtNum(cur.stats.projects_partially_allocated)} partial</span>
            <span><span className="dot bad" />{fmt.fmtNum(cur.stats.projects_unassigned)} unassigned</span>
          </>}
        </span>
      </nav>

      <main className="content">

        {!run && tab !== 'forecast' && tab !== 'forecast_method' && tab !== 'methodology' && (
          <div style={{
            display:'flex', alignItems:'center', justifyContent:'center',
            minHeight:'60vh', width:'100%',
          }}>
            <div style={{
              background:'var(--paper)', border:'1px solid var(--rule)',
              borderRadius:10, padding:'40px 48px', maxWidth:440, width:'100%',
              boxShadow:'var(--shadow)',
              display:'flex', flexDirection:'column', alignItems:'center', gap:20,
            }}>
              <div style={{ fontFamily:'var(--serif)', fontSize:22, fontWeight:500, color:'var(--ink)', textAlign:'center' }}>
                CanConstruct ABM
              </div>
              <div style={{ color:'var(--ink-3)', fontSize:13, textAlign:'center', lineHeight:1.5 }}>
                Upload a results database produced by the simulation backend to explore allocation outcomes.
              </div>
              {uploadError && (
                <div style={{
                  width:'100%', padding:'8px 12px',
                  background:'var(--bg-alt)', border:'1px solid var(--rule)',
                  borderLeft:'3px solid var(--bad)',
                  fontFamily:'var(--mono)', fontSize:11, color:'var(--ink-2)',
                  borderRadius:4,
                }}>
                  <b style={{ color:'var(--bad)' }}>Upload failed</b> — {uploadError}
                </div>
              )}
              <button className="btn" style={{ padding:'10px 28px', fontSize:13, fontWeight:600 }}
                      onClick={() => fileInputRef.current?.click()}>
                ↑ Upload results DB
              </button>
              <div style={{ color:'var(--ink-3)', fontSize:11 }}>
                Accepts <span style={{ fontFamily:'var(--mono)' }}>.sqlite3</span> or <span style={{ fontFamily:'var(--mono)' }}>.json</span>
              </div>
              <button className="btn ghost"
                      style={{ padding:'6px 14px', fontSize:11, fontWeight:500 }}
                      onClick={() => setTab('methodology')}>
                View Methodology →
              </button>
            </div>
          </div>
        )}

        {tab === 'forecast' && (
          <Forecast result={forecastResult}
                    status={forecastStatus}
                    error={forecastError}
                    params={scenarioParams}
                    onRun={runForecast}
                    onSetParam={(k, v) => setTweak(k, v)}
                    onSetShocks={(shocks) => setTweak('shocks', shocks)}
                    onSeedSimulation={() => fileInputRef.current?.click()} />
        )}
        {tab === 'forecast_method' && <ForecastMethodology />}

        {run && tab === 'overview' && (
          <Overview run={run} year={year}
                    regionFilter={regionFilter}
                    setRegionFilter={setRegionFilter}
                    showUnassigned={t.showUnassigned}
                    onOpenProject={setSelectedProject} />
        )}
        {run && tab === 'heatmap' && (
          <Heatmap run={run} year={year} />
        )}
        {run && tab === 'projects' && (
          <ProjectsTable run={run} year={year}
                         regionFilter={regionFilter}
                         setRegionFilter={setRegionFilter}
                         onOpenProject={setSelectedProject}
                         onOpenCompany={setSelectedCompany} />
        )}
        {run && tab === 'companies' && (
          <CompaniesTable run={run} year={year}
                          regionFilter={regionFilter}
                          onOpenCompany={setSelectedCompany} />
        )}
        {tab === 'methodology' && (
          <Methodology />
        )}
        <div className="footer">
          Copyright © 2026 CanConstruct. All rights reserved.
        </div>
      </main>

      {selectedProject && (
        <ProjectDrawer project={selectedProject} run={run} year={year}
                       onClose={()=>setSelectedProject(null)}
                       onOpenCompany={(c)=>{ setSelectedProject(null); setTimeout(()=>setSelectedCompany(c), 150); }} />
      )}
      {selectedCompany && (
        <CompanyDrawer company={selectedCompany} run={run} year={year}
                       onClose={()=>setSelectedCompany(null)}
                       onOpenProject={(p)=>{ setSelectedCompany(null); setTimeout(()=>setSelectedProject(p), 150); }} />
      )}

      <TweaksPanel>
        <TweakSection label="Theme" />
        <TweakToggle label="Dark mode" value={t.dark} onChange={v=>setTweak('dark', v)} />
        <TweakRadio label="Density" value={t.density}
                    options={['compact','regular']}
                    onChange={v=>setTweak('density', v)} />

        <TweakSection label="Filters" />
        <TweakSelect label="Region filter" value={t.regionFilter}
                     options={[
                       { value:'all', label:'All regions' },
                       ...ABM.REGIONS.map(r => ({ value:r.name, label:r.name }))
                     ]}
                     onChange={v=>setTweak('regionFilter', v)} />

        <TweakSection label="Overview" />
        <TweakToggle label="Show unassigned table" value={t.showUnassigned}
                     onChange={v=>setTweak('showUnassigned', v)} />
      </TweaksPanel>
    </div>
  );
}
