/* forecast-api.js
 * ------------------------------------------------------------------
 * Mock client for the Resilience Hub forecast service.
 *
 * Until the Python backend is wired up, this module STANDS IN as the
 * server: deterministic generators produce historical baselines and
 * ensemble forecasts whenever the UI asks for them.
 *
 * Real backend integration: replace runForecast and getBaseline with
 * fetch() calls to the matching endpoints. The JSON shapes are stable.
 *
 * ── Proposed REST schema ──────────────────────────────────────────
 *
 *   GET  /api/forecast/baseline
 *     → {
 *         regions: [{ name, short, code }],
 *         building_types: [...],
 *         baseline_year: 2024,
 *         historical: {
 *           [region]: {
 *             [building_type]: [{ year:number, value:number, count:number }]
 *           }
 *         }
 *       }
 *
 *   POST /api/forecast/run
 *     body: {
 *       gdp_chg:   number,           // percent, e.g. 2.5
 *       pop_chg:   number,           // percent
 *       inflation: number,           // percent
 *       fiscal:    number,           // -1..+1
 *       horizon_year: number,        // 2025..2050
 *       shocks: [{ id, type, year, duration, magnitude }]
 *     }
 *     → {
 *         scenario_id: string,
 *         params: { ...echoed inputs },
 *         baseline_year: 2024,
 *         horizon_year: number,
 *         regions: [{
 *           name, short,
 *           historical:   [{year, value, count}],
 *           by_building_type: {
 *             [bt]: {
 *               historical: [...],
 *               forecasts:  { gam:[...], ecm:[...], huber:[...], ensemble:[...] }
 *             }
 *           },
 *           forecasts_total: {
 *             gam:[...], ecm:[...], huber:[...], ensemble:[...]
 *           }
 *         }],
 *         national: {
 *           total_value_2024:        number,
 *           total_count_2024:        number,
 *           total_value_horizon:     { gam, ecm, huber, ensemble },
 *           total_count_horizon:     { gam, ecm, huber, ensemble },
 *           annual_growth_pct:       { gam, ecm, huber, ensemble }
 *         },
 *         method_meta: {
 *           gam:      { label, blurb, color },
 *           ecm:      { ... },
 *           huber:    { ... },
 *           ensemble: { ... }
 *         },
 *         simulation_input_url: string  // optional handover to ABM stage
 *       }
 *
 *   POST /api/forecast/run-simulation
 *     body: { scenario_id: string }
 *     → { job_id, status, sqlite_url? }
 * ------------------------------------------------------------------
 */

export const REGIONS = [
  { name: 'Auckland Region',       short: 'AKL' },
  { name: 'Waikato Region',        short: 'WKO' },
  { name: 'Wellington Region',     short: 'WLG' },
  { name: 'Rest of North Island',  short: 'RNI' },
  { name: 'Canterbury Region',     short: 'CAN' },
  { name: 'Rest of South Island',  short: 'RSI' },
];

// Forecast-side building types (merged buckets per project.md §3)
export const BUILDING_TYPES = ['Residential', 'Institutional', 'Commercial', 'Industrial'];

export const METHODS = ['gam', 'ecm', 'huber', 'ensemble'];

// Shock metadata: each magnitude (%) is scaled by a per-BT weight before applying.
export const SHOCK_TYPES = {
  earthquake:   { label: 'Earthquake',         blurb: 'Disrupts sites & supply chains; 1–3 yr impact.',
                  bt_weights: { Residential: 0.95, Institutional: 1.10, Commercial: 1.05, Industrial: 0.85 },
                  default: { duration: 2, magnitude: -18 } },
  flood:        { label: 'Flood',              blurb: 'Regional infrastructure damage; rapid hit.',
                  bt_weights: { Residential: 1.00, Institutional: 0.95, Commercial: 1.00, Industrial: 1.10 },
                  default: { duration: 1, magnitude: -10 } },
  pandemic:     { label: 'Pandemic',           blurb: 'On-site work halts; commercial fit-out collapses.',
                  bt_weights: { Residential: 0.85, Institutional: 0.95, Commercial: 1.25, Industrial: 1.05 },
                  default: { duration: 2, magnitude: -15 } },
  stock_market: { label: 'Stock-market crash', blurb: 'Project finance dries up; value > counts.',
                  bt_weights: { Residential: 0.90, Institutional: 0.80, Commercial: 1.20, Industrial: 1.10 },
                  default: { duration: 3, magnitude: -12 } },
  custom:       { label: 'Custom shock',       blurb: 'User-defined; applied uniformly across BTs.',
                  bt_weights: { Residential: 1.00, Institutional: 1.00, Commercial: 1.00, Industrial: 1.00 },
                  default: { duration: 1, magnitude: -10 } },
};

export const METHOD_META = {
  gam:      { label: 'GAM',         color: '#4a6b3a',
              blurb: 'Generalised additive model — flexible smooth response to each macro driver.' },
  ecm:      { label: 'ECM',         color: '#2f6fb0',
              blurb: 'Error-correction style — short-run dynamics around long-run cointegration.' },
  huber:    { label: 'Robust',      color: '#b78a2b',
              blurb: 'Huber robust regression — down-weights outlier years to stabilise the mean path.' },
  ensemble: { label: 'Ensemble',    color: '#b04a2f',
              blurb: 'Weighted average of GAM, ECM, and Robust; the headline series.' },
};

// Anchor: 2024 baseline values per region per building type, in NZD millions
// Numbers are illustrative — Python backend will overwrite with real present_values.
const BASE_VALUE_2024_M = {
  'Auckland Region':       { Residential: 6800, Institutional: 1900, Commercial: 3200, Industrial: 1200 },
  'Waikato Region':        { Residential: 1400, Institutional:  420, Commercial:  680, Industrial:  380 },
  'Wellington Region':     { Residential: 2200, Institutional:  780, Commercial: 1100, Industrial:  340 },
  'Rest of North Island':  { Residential: 2900, Institutional:  820, Commercial: 1180, Industrial:  610 },
  'Canterbury Region':     { Residential: 2600, Institutional:  640, Commercial: 1240, Industrial:  500 },
  'Rest of South Island':  { Residential: 1100, Institutional:  280, Commercial:  520, Industrial:  240 },
};
// Approx project counts per region per building type per year (2024)
const BASE_COUNT_2024 = {
  'Auckland Region':       { Residential: 4200, Institutional: 110, Commercial: 280, Industrial:  90 },
  'Waikato Region':        { Residential:  980, Institutional:  34, Commercial:  62, Industrial:  31 },
  'Wellington Region':     { Residential: 1400, Institutional:  58, Commercial:  92, Industrial:  28 },
  'Rest of North Island':  { Residential: 2100, Institutional:  72, Commercial: 110, Industrial:  46 },
  'Canterbury Region':     { Residential: 1700, Institutional:  52, Commercial: 108, Industrial:  41 },
  'Rest of South Island':  { Residential:  820, Institutional:  24, Commercial:  46, Industrial:  19 },
};

// Deterministic PRNG (mulberry32)
function mulberry32(seed) {
  return function () {
    let t = seed += 0x6D2B79F5;
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}
function hashStr(s) {
  let h = 2166136261 >>> 0;
  for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = Math.imul(h, 16777619); }
  return h >>> 0;
}

// ---- Historical 2015–2024 synthesis (gentle wave + region drift + COVID dip in 2020-21) ----
function buildHistorical(region, bt) {
  const rng = mulberry32(hashStr(region + '|' + bt + '|hist'));
  const base24 = BASE_VALUE_2024_M[region][bt];
  const baseCt = BASE_COUNT_2024[region][bt];
  const series = [];
  for (let y = 2015; y <= 2024; y++) {
    const t = (y - 2015) / 9;
    let factor = 0.72 + 0.28 * t + 0.04 * Math.sin(t * Math.PI * 2.1);
    if (y === 2020) factor *= 0.82;
    if (y === 2021) factor *= 0.92;
    if (y === 2024) factor = 1.0;
    const value = base24 * factor * (0.97 + rng() * 0.06);
    const count = Math.round(baseCt * factor * (0.95 + rng() * 0.10));
    series.push({ year: y, value: round1(value), count });
  }
  return series;
}

// ---- Forecast 2025..horizon ----
function buildForecast(region, bt, params, method, horizon_year) {
  const { gdp_chg, pop_chg, inflation, fiscal, shocks } = params;
  const rng = mulberry32(hashStr(region + '|' + bt + '|' + method));
  const base24V = BASE_VALUE_2024_M[region][bt];
  const base24C = BASE_COUNT_2024[region][bt];

  const elas = {
    Residential:   { gdp: 0.55, pop: 1.10, infl: 1.00, fiscal_sens: 0.012 },
    Institutional: { gdp: 0.30, pop: 0.55, infl: 1.00, fiscal_sens: 0.024 },
    Commercial:    { gdp: 0.85, pop: 0.40, infl: 1.00, fiscal_sens: 0.006 },
    Industrial:    { gdp: 0.70, pop: 0.25, infl: 1.00, fiscal_sens: -0.004 },
  }[bt];

  const methodBias = { gam: 0.0, ecm: -0.2, huber: -0.1, ensemble: -0.07 }[method];
  const fiscalMult = 1 + fiscal * elas.fiscal_sens;

  const realPct = (elas.gdp * gdp_chg + elas.pop * pop_chg) / (elas.gdp + elas.pop) + methodBias;
  const realG = realPct / 100;
  const inflG = (inflation / 100) * elas.infl;

  const shockMult = {};
  for (const sh of (shocks || [])) {
    const meta = SHOCK_TYPES[sh.type] || SHOCK_TYPES.custom;
    const w = meta.bt_weights[bt] ?? 1.0;
    const dur = Math.max(1, Math.round(sh.duration || 1));
    const peak = (sh.magnitude || 0) * w / 100;
    for (let i = 0; i < dur; i++) {
      const tFrac = dur === 1 ? 1 : 1 - Math.abs((i - (dur - 1) / 2) / ((dur - 1) / 2));
      const yr = sh.year + i;
      shockMult[yr] = (shockMult[yr] ?? 1) * (1 + peak * tFrac);
    }
  }

  const series = [];
  let v = base24V, c = base24C;
  for (let y = 2025; y <= horizon_year; y++) {
    const yearlyValueG = (1 + realG) * (1 + inflG) * fiscalMult;
    const yearlyCountG = (1 + realG) * fiscalMult;
    const wobble = (rng() - 0.5) * (method === 'huber' ? 0.004 : method === 'gam' ? 0.012 : 0.008);
    v = v * (yearlyValueG + wobble);
    c = c * (yearlyCountG + wobble * 0.5);
    const sm = shockMult[y] ?? 1;
    series.push({ year: y, value: round1(v * sm), count: Math.max(1, Math.round(c * sm)) });
  }
  return series;
}

function round1(n) { return Math.round(n * 10) / 10; }

function delay(ms) { return new Promise(r => setTimeout(r, ms)); }
function clampInt(n, lo, hi) { n = Math.round(n); return Math.min(hi, Math.max(lo, n)); }
function clampNum(n, lo, hi) { return Math.min(hi, Math.max(lo, n)); }

export async function getBaseline() {
  await delay(120);
  const historical = {};
  for (const r of REGIONS) {
    historical[r.name] = {};
    for (const bt of BUILDING_TYPES) {
      historical[r.name][bt] = buildHistorical(r.name, bt);
    }
  }
  return {
    regions: REGIONS,
    building_types: BUILDING_TYPES,
    baseline_year: 2024,
    historical,
  };
}

export async function runForecast(params) {
  await delay(700 + Math.random() * 600);

  const p = {
    gdp_chg:      Number(params.gdp_chg ?? 2.0),
    pop_chg:      Number(params.pop_chg ?? 1.2),
    inflation:    Number(params.inflation ?? 2.5),
    fiscal:       clampNum(Number(params.fiscal ?? 0), -1, 1),
    horizon_year: clampInt(params.horizon_year ?? 2035, 2025, 2050),
    shocks:       Array.isArray(params.shocks)
                    ? params.shocks
                        .filter(s => s && s.type && SHOCK_TYPES[s.type])
                        .map(s => ({
                          id: s.id,
                          type: s.type,
                          year: clampInt(s.year ?? 2025, 2025, 2050),
                          duration: clampInt(s.duration ?? 1, 1, 10),
                          magnitude: clampNum(Number(s.magnitude ?? 0), -50, 50),
                        }))
                    : [],
  };

  const regions = REGIONS.map(r => {
    const by_building_type = {};
    const forecasts_total = Object.fromEntries(METHODS.map(m => [m, []]));
    const historical_total = [];
    for (const bt of BUILDING_TYPES) {
      const hist = buildHistorical(r.name, bt);
      const forecasts = {};
      for (const m of METHODS) {
        forecasts[m] = buildForecast(r.name, bt, p, m, p.horizon_year);
      }
      by_building_type[bt] = { historical: hist, forecasts };

      for (let i = 0; i < hist.length; i++) {
        if (!historical_total[i]) historical_total[i] = { year: hist[i].year, value: 0, count: 0 };
        historical_total[i].value += hist[i].value;
        historical_total[i].count += hist[i].count;
      }
      for (const m of METHODS) {
        const arr = forecasts[m];
        for (let i = 0; i < arr.length; i++) {
          if (!forecasts_total[m][i]) forecasts_total[m][i] = { year: arr[i].year, value: 0, count: 0 };
          forecasts_total[m][i].value += arr[i].value;
          forecasts_total[m][i].count += arr[i].count;
        }
      }
    }
    historical_total.forEach(x => { x.value = round1(x.value); });
    for (const m of METHODS) forecasts_total[m].forEach(x => { x.value = round1(x.value); });

    return {
      name:  r.name,
      short: r.short,
      historical: historical_total,
      by_building_type,
      forecasts_total,
    };
  });

  const nat_hist_2024 = regions.reduce((acc, r) => {
    const last = r.historical[r.historical.length - 1];
    acc.value += last.value;
    acc.count += last.count;
    return acc;
  }, { value: 0, count: 0 });

  const total_value_horizon = {};
  const total_count_horizon = {};
  const annual_growth_pct = {};
  for (const m of METHODS) {
    let tv = 0, tc = 0;
    for (const r of regions) {
      const last = r.forecasts_total[m][r.forecasts_total[m].length - 1];
      tv += last.value;
      tc += last.count;
    }
    total_value_horizon[m] = round1(tv);
    total_count_horizon[m] = Math.round(tc);
    const years = p.horizon_year - 2024;
    annual_growth_pct[m] = round1((Math.pow(tv / nat_hist_2024.value, 1 / years) - 1) * 100);
  }

  return {
    scenario_id: `sc_${Date.now().toString(36)}_${Math.floor(Math.random() * 1e4).toString(36)}`,
    params: p,
    baseline_year: 2024,
    horizon_year: p.horizon_year,
    regions,
    national: {
      total_value_2024: round1(nat_hist_2024.value),
      total_count_2024: nat_hist_2024.count,
      total_value_horizon,
      total_count_horizon,
      annual_growth_pct,
    },
    method_meta: METHOD_META,
    simulation_input_url: null,
  };
}

export const ForecastAPI = {
  REGIONS,
  BUILDING_TYPES,
  METHODS,
  METHOD_META,
  SHOCK_TYPES,
  getBaseline,
  runForecast,
};
