// Tables: Projects + Companies with sort/filter/click-to-detail
import React, { useState as useStateT, useMemo as useMemoT } from 'react';
import { fmt } from './utils.js';
import { ABM } from './data.js';
import { VirtualScrollTable } from './virtualDataTable.jsx';

function useSortable(rows, defaultKey, defaultDir = 'desc') {
  const [sortKey, setSortKey] = useStateT(defaultKey);
  const [sortDir, setSortDir] = useStateT(defaultDir);
  const sorted = useMemoT(() => {
    const out = [...rows];
    out.sort((a, b) => {
      const av = a[sortKey], bv = b[sortKey];
      if (typeof av === 'number' && typeof bv === 'number') return sortDir === 'asc' ? av - bv : bv - av;
      return sortDir === 'asc'
        ? String(av ?? '').localeCompare(String(bv ?? ''))
        : String(bv ?? '').localeCompare(String(av ?? ''));
    });
    return out;
  }, [rows, sortKey, sortDir]);
  const onSort = (k) => {
    if (sortKey === k) setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    else { setSortKey(k); setSortDir('desc'); }
  };
  return { sorted, sortKey, sortDir, onSort };
}

const NUM_TH_SUBTITLE = {
  fontSize: 9,
  color: 'var(--ink-3)',
  fontWeight: 400,
  lineHeight: 1.2,
};

/** Right-aligned numeric column header: main title + smaller subtitle (saves width). */
function NumThStacked({ sortId, onSort, cls, title, subtitle }) {
  return (
    <th
      onClick={() => onSort(sortId)}
      className={`num ${cls(sortId)}`}
      style={{ verticalAlign: 'bottom', whiteSpace: 'normal' }}
    >
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'flex-end',
          gap: 2,
          lineHeight: 1.15,
        }}
      >
        <span>{title}</span>
        <span style={NUM_TH_SUBTITLE}>{subtitle}</span>
      </div>
    </th>
  );
}

export function ProjectsTable({ run, year, regionFilter, setRegionFilter, onOpenProject, onOpenCompany }) {
  const cur = run[year];
  const fm = fmt;
  const [q, setQ] = useStateT('');
  const [statusF, setStatusF] = useStateT('all');
  const [catF, setCatF] = useStateT('all');

  const rows = useMemoT(() => cur.projects
    .filter(p => !regionFilter || p.region === regionFilter)
    .filter(p => statusF === 'all' || p.status === statusF)
    .filter(p => catF === 'all' || p.category === catF)
    .filter(p => !q || p.name.toLowerCase().includes(q.toLowerCase()) || String(p.project_id).includes(q))
    .map(p => ({
      ...p,
      regionLabel: ABM.REGIONS.find(r => r.name === p.region)?.name ?? p.region,
      mainContractorName: p.main_contractor_id
        ? cur.companies.find(c => c.company_id === p.main_contractor_id)?.name ?? '—'
        : '—',
      subsCount: p.subcontractors.length,
      allocPct: p.paw > 0 ? (p.main_allocated + p.subcontractors.reduce((s,sc)=>s+sc.allocated,0)) / p.paw : 0,
    })),
  [cur, regionFilter, q, statusF, catF]);

  const { sorted, sortKey, sortDir, onSort } = useSortable(rows, 'value', 'desc');
  const cls = (k) => 'col ' + (sortKey === k ? `sort-${sortDir}` : '');
  const projectsScrollResetKey = `${year}\0${regionFilter ?? ''}\0${q}\0${statusF}\0${catF}\0${sortKey}\0${sortDir}`;

  return (
    <div>
      <div className="section-h">
        <div className="kicker">PROJECTS</div>
        <div>
          <h2>Project ledger</h2>
          <p className="sub">{fm.fmtNum(rows.length)} projects in scope. Sort any column; click any row for the full main + subcontractor breakdown.</p>
        </div>
      </div>

      <div className="filter-row">
        <input type="search" placeholder="Search project name or ID…" value={q} onChange={e=>setQ(e.target.value)} />
        <div className="seg">
          {['all','fully_allocated','partial','unassigned','stuck'].map(s => (
            <button key={s} className={statusF === s ? 'active' : ''} onClick={()=>setStatusF(s)}>
              {s === 'all' ? 'All' : s.replace('_',' ')}
            </button>
          ))}
        </div>
        <select value={catF} onChange={e=>setCatF(e.target.value)}>
          <option value="all">All categories</option>
          {ABM.PROJECT_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
        <select
          value={regionFilter ?? 'all'}
          onChange={e => setRegionFilter(e.target.value === 'all' ? null : e.target.value)}
          aria-label="Filter by region"
        >
          <option value="all">All regions</option>
          {ABM.REGIONS.map(r => <option key={r.name} value={r.name}>{r.name}</option>)}
        </select>
        <span style={{ marginLeft: 'auto', color: 'var(--ink-3)', fontSize: 11 }}>
          {fm.fmtNum(rows.length)} of {fm.fmtNum(cur.projects.length)}
        </span>
      </div>

      <div className="panel" style={{ padding: '12px 18px' }}>
        <div className="table-wrap">
          <VirtualScrollTable
            colSpan={10}
            rows={sorted}
            resetScrollDeps={projectsScrollResetKey}
            head={(
              <thead>
                <tr>
                  <th onClick={()=>onSort('name')} className={cls('name')}>Project</th>
                  <th onClick={()=>onSort('category')} className={cls('category')}>Category</th>
                  <th onClick={()=>onSort('regionLabel')} className={cls('regionLabel')}>Region</th>
                  <th onClick={()=>onSort('value')} className={`num ${cls('value')}`}>Value</th>
                  <th onClick={()=>onSort('paw')} className={`num ${cls('paw')}`}>PAW</th>
                  <th onClick={()=>onSort('duration')} className={`num ${cls('duration')}`}>Yrs</th>
                  <th onClick={()=>onSort('mainContractorName')} className={cls('mainContractorName')}>Main</th>
                  <th onClick={()=>onSort('subsCount')} className={`num ${cls('subsCount')}`}>Subs</th>
                  <th onClick={()=>onSort('allocPct')} className={`num ${cls('allocPct')}`}>Alloc</th>
                  <th onClick={()=>onSort('status')} className={cls('status')}>Status</th>
                </tr>
              </thead>
            )}
            renderRow={(p) => (
              <tr key={p.project_id} className="clickable" onClick={()=>onOpenProject(p)}>
                <td className="label">{p.name}<div style={{ fontSize:10, color:'var(--ink-3)' }}>#{p.project_id}</div></td>
                <td><span className="tag">{p.category}</span></td>
                <td className="dim">{p.regionLabel}</td>
                <td className="num">{fm.fmtMoney(p.value)}</td>
                <td className="num">{fm.fmtMoney(p.paw)}</td>
                <td className="num dim">{p.duration}</td>
                <td className="dim" onClick={(e)=>{
                  if (p.main_contractor_id) {
                    e.stopPropagation();
                    const c = cur.companies.find(c => c.company_id === p.main_contractor_id);
                    if (c) onOpenCompany(c);
                  }
                }} style={{ cursor: p.main_contractor_id ? 'pointer' : 'default', color: p.main_contractor_id ? 'var(--ink)' : 'var(--ink-3)' }}>
                  {p.mainContractorName}
                </td>
                <td className="num">{p.subsCount}</td>
                <td className="num">{fm.fmtPct(p.allocPct, 0)}</td>
                <td>
                  <span className={`pill ${
                    p.status === 'fully_allocated' ? 'full' :
                    p.status === 'partial' ? 'partial' :
                    p.status === 'stuck' ? 'stuck' : 'unassigned'
                  }`}>
                    {p.status === 'fully_allocated' ? 'FULL' :
                     p.status === 'partial' ? 'PARTIAL' :
                     p.status === 'stuck' ? 'STUCK' : 'UNASSIGNED'}
                  </span>
                </td>
              </tr>
            )}
          />
          <p style={{ textAlign:'center', fontSize:11, color:'var(--ink-3)', marginTop:10 }}>
            {fm.fmtNum(sorted.length)} matching projects — scroll the list to see all rows.
          </p>
        </div>
      </div>
    </div>
  );
}

export function CompaniesTable({ run, year, regionFilter, onOpenCompany }) {
  const cur = run[year];
  const fm = fmt;
  const [q, setQ] = useStateT('');
  const [roleF, setRoleF] = useStateT('all');
  const [reachF, setReachF] = useStateT('all');

  const rows = useMemoT(() => cur.companies
    .filter(c => !regionFilter || c.region === regionFilter || c.reach === 'National'
                 || (c.reach === 'Multi-region' && (ABM.REGIONS.find(r=>r.name===c.region)?.island === ABM.REGIONS.find(r=>r.name===regionFilter)?.island)))
    .filter(c => roleF === 'all' || c.role === roleF)
    .filter(c => reachF === 'all' || c.reach === reachF)
    .filter(c => !q || c.name.toLowerCase().includes(q.toLowerCase()) || c.category.toLowerCase().includes(q.toLowerCase()))
    .map(c => {
      const t0 = Number(c.initial_turnover) || 0;
      const t1 = Number(c.turnover) || 0;
      return {
        ...c,
        regionLabel: ABM.REGIONS.find(r => r.name === c.region)?.name ?? c.region,
        utilisation: t0 > 0 ? (t0 - t1) / t0 : 0,
        awarded: c.awarded_main.length + c.awarded_sub.length,
      };
    }),
  [cur, regionFilter, q, roleF, reachF]);

  const { sorted, sortKey, sortDir, onSort } = useSortable(rows, 'rac', 'desc');
  const cls = (k) => sortKey === k ? `sort-${sortDir}` : '';
  const companiesScrollResetKey = `${year}\0${regionFilter ?? ''}\0${q}\0${roleF}\0${reachF}\0${sortKey}\0${sortDir}`;

  return (
    <div>
      <div className="section-h">
        <div className="kicker">COMPANIES</div>
        <div>
          <h2>Company directory</h2>
          <p className="sub">{fm.fmtNum(rows.length)} firms in scope. Utilisation = (start turnover − remaining turnover) ÷ start turnover. Initial CAC is at year open; RAC is remaining annual capacity after awards (equal to final CAC in the model). Click any firm for detail.</p>
        </div>
      </div>

      <div className="filter-row">
        <input type="search" placeholder="Search company name or category…" value={q} onChange={e=>setQ(e.target.value)} />
        <div className="seg">
          {['all','main','sub'].map(s => (
            <button key={s} className={roleF === s ? 'active' : ''} onClick={()=>setRoleF(s)}>
              {s === 'all' ? 'All roles' : s === 'main' ? 'Main' : 'Sub'}
            </button>
          ))}
        </div>
        <div className="seg">
          {['all','National','Multi-region','Regional'].map(s => (
            <button key={s} className={reachF === s ? 'active' : ''} onClick={()=>setReachF(s)}>
              {s === 'all' ? 'All reach' : s}
            </button>
          ))}
        </div>
        <span style={{ marginLeft: 'auto', color: 'var(--ink-3)', fontSize: 11 }}>
          {fm.fmtNum(rows.length)} of {fm.fmtNum(cur.companies.length)}
        </span>
      </div>

      <div className="panel" style={{ padding: '12px 18px' }}>
        <div className="table-wrap">
          <VirtualScrollTable
            colSpan={11}
            rows={sorted}
            resetScrollDeps={companiesScrollResetKey}
            head={(
              <thead>
                <tr>
                  <th onClick={()=>onSort('name')} className={cls('name')}>Company</th>
                  <th onClick={()=>onSort('category')} className={cls('category')}>Category</th>
                  <th onClick={()=>onSort('regionLabel')} className={cls('regionLabel')}>Base</th>
                  <th onClick={()=>onSort('reach')} className={cls('reach')}>Reach</th>
                  <th onClick={()=>onSort('size_band')} className={cls('size_band')}>Size band</th>
                  <NumThStacked sortId="initial_turnover" onSort={onSort} cls={cls} title="Turnover" subtitle="(initial)" />
                  <NumThStacked sortId="turnover" onSort={onSort} cls={cls} title="Turnover" subtitle="(remaining)" />
                  <NumThStacked sortId="initial_cac" onSort={onSort} cls={cls} title="Capacity" subtitle="(initial)" />
                  <NumThStacked sortId="rac" onSort={onSort} cls={cls} title="Capacity" subtitle="(remaining)" />
                  <th onClick={()=>onSort('utilisation')} className={`num ${cls('utilisation')}`}>Util.</th>
                  <th onClick={()=>onSort('awarded')} className={`num ${cls('awarded')}`}>Awarded</th>
                </tr>
              </thead>
            )}
            renderRow={(c) => (
              <tr key={c.company_id} className="clickable" onClick={()=>onOpenCompany(c)}>
                <td className="label">{c.name}<div style={{ fontSize:10, color:'var(--ink-3)' }}>#{c.company_id} · {c.role === 'main' ? 'Main' : 'Sub'}</div></td>
                <td><span className="tag">{c.category}</span></td>
                <td className="dim">{c.regionLabel}</td>
                <td className="dim">{c.reach}</td>
                <td className="dim">{c.size_band}</td>
                <td className="num">{fm.fmtMoney(c.initial_turnover ?? c.turnover)}</td>
                <td className="num">{fm.fmtMoney(c.turnover)}</td>
                <td className="num">{fm.fmtMoney(c.initial_cac ?? c.cac)}</td>
                <td className="num"><b>{fm.fmtMoney(c.rac)}</b></td>
                <td className="num">
                  <UtilBar pct={c.utilisation} />
                </td>
                <td className="num">{c.awarded}</td>
              </tr>
            )}
          />
          <p style={{ textAlign:'center', fontSize:11, color:'var(--ink-3)', marginTop:10 }}>
            {fm.fmtNum(sorted.length)} matching firms — scroll the list to see all rows.
          </p>
        </div>
      </div>
    </div>
  );
}

function UtilBar({ pct }) {
  return (
    <div style={{ display:'inline-flex', alignItems:'center', gap:8, justifyContent:'flex-end' }}>
      <div style={{ width:60, height:6, background:'var(--rule-2)', position:'relative' }}>
        <div style={{ position:'absolute', inset:0, right:'auto', width:`${Math.min(100, pct*100)}%`, background: pct >= 0.95 ? 'var(--bad)' : pct >= 0.6 ? 'var(--warn)' : 'var(--good)' }} />
      </div>
      <span style={{ fontSize:11, fontVariantNumeric:'tabular-nums', minWidth:36, textAlign:'right' }}>{(pct*100).toFixed(0)}%</span>
    </div>
  );
}

