// Heatmap, project detail, company detail screens

import React, { useState as useStateD, useMemo as useMemoD, useEffect as useEffectD, useRef as useRefD } from 'react';
import { Chart } from './charts.jsx';
import { fmt } from './utils.js';
import { ABM } from './data.js';

/** Same tolerance as `simulation.constants.ALLOCATION_EPSILON` — keeps this trace aligned with the allocator. */
const ALLOCATION_EPSILON = 1e-6;

/**
 * Click (?): opens; click outside or (?) again: closes. Plain-language explanations for eligibility metrics.
 */
function HelpTip({ label, children }) {
  const [open, setOpen] = useStateD(false);
  const wrapRef = useRefD(null);
  useEffectD(() => {
    if (!open) return;
    function onDocDown(e) {
      if (wrapRef.current && !wrapRef.current.contains(e.target)) setOpen(false);
    }
    document.addEventListener('mousedown', onDocDown);
    return () => document.removeEventListener('mousedown', onDocDown);
  }, [open]);
  return (
    <span className="help-tip" ref={wrapRef}>
      <button
        type="button"
        className="help-tip__btn"
        aria-expanded={open}
        aria-label={label}
        onClick={() => setOpen(v => !v)}
      >
        ?
      </button>
      {open ? (
        <div className="help-tip__pop" role="tooltip">
          {children}
        </div>
      ) : null}
    </span>
  );
}

export function Heatmap({ run, year, onSelectCell }) {
  const cur = run[year];
  const fm = fmt;
  const regions = ABM.REGIONS;
  const cats = ABM.PROJECT_CATEGORIES;

  // unassigned PAW per (region, cat)
  const cells = useMemoD(() => {
    const m = {};
    for (const r of regions) m[r.name] = {};
    for (const r of regions) for (const c of cats) m[r.name][c] = { paw: 0, n: 0, total: 0, totalN: 0 };
    for (const p of cur.projects) {
      const cell = m[p.region]?.[p.category];
      if (!cell) continue;
      cell.total += p.paw; cell.totalN += 1;
      if (p.main_contractor_id == null) { cell.paw += p.paw; cell.n += 1; }
      else if (p.remaining_workload > 1) { cell.paw += p.remaining_workload; }
    }
    return m;
  }, [cur]);

  const max = Math.max(0.0001, ...regions.flatMap(r => cats.map(c => cells[r.name][c].paw)));

  return (
    <div>
      <div className="section-h">
        <div className="kicker">BOTTLENECKS</div>
        <div>
          <h2>Region × category heatmap</h2>
          <p className="sub">Unallocated annual workload by region (rows) and project category (columns). Darker cells indicate where capacity is missing — usually heavy civil categories outside the main centres.</p>
        </div>
      </div>

      <div className="panel">
        <div style={{ overflowX:'auto' }}>
          <table className="heat" style={{ minWidth: 720 }}>
            <thead>
              <tr>
                <th style={{ width: 160 }}></th>
                {cats.map(c => (
                  <th key={c} className="col"><span>{c}</span></th>
                ))}
                <th className="col"><span>Row total</span></th>
              </tr>
            </thead>
            <tbody>
              {regions.map(r => {
                const rowTot = cats.reduce((s,c)=>s+cells[r.name][c].paw, 0);
                return (
                  <tr key={r.name}>
                    <td className="row-l">
                      {r.name}
                      <div style={{ fontSize:10, color:'var(--ink-3)', fontWeight:400 }}>{r.island} Island</div>
                    </td>
                    {cats.map(c => {
                      const v = cells[r.name][c].paw;
                      const intensity = v / max;
                      const bg = `color-mix(in srgb, var(--accent) ${(intensity*92).toFixed(0)}%, var(--bg-alt))`;
                      return (
                        <td key={c}
                            className={v <= 0.001 ? 'zero' : ''}
                            style={{ background: bg, color: intensity > 0.55 ? 'var(--bg)' : 'var(--ink)' }}
                            title={`${r.name} × ${c}\n${cells[r.name][c].n} unassigned, ${fm.fmtMoney(v)} unallocated PAW`}
                            onClick={() => onSelectCell && onSelectCell({ region: r.name, category: c })}>
                          <span className="v">{v > 0 ? fm.fmtMoney(v) : '—'}</span>
                        </td>
                      );
                    })}
                    <td style={{ background:'var(--bg)', fontWeight:600, padding:'0 10px' }}>
                      <span className="v">{fm.fmtMoney(rowTot)}</span>
                    </td>
                  </tr>
                );
              })}
              <tr>
                <td className="row-l">Column total</td>
                {cats.map(c => {
                  const v = regions.reduce((s,r)=>s+cells[r.name][c].paw, 0);
                  return (
                    <td key={c} style={{ background:'var(--bg)', fontWeight:600, padding:'0 6px' }}>
                      <span className="v">{fm.fmtMoney(v)}</span>
                    </td>
                  );
                })}
                <td style={{ background:'var(--ink)', color:'var(--bg)', fontWeight:700 }}>
                  <span className="v">{fm.fmtMoney(regions.reduce((s,r)=>s+cats.reduce((q,c)=>q+cells[r.name][c].paw,0),0))}</span>
                </td>
              </tr>
            </tbody>
          </table>
        </div>

        <div className="legend" style={{ marginTop:14, justifyContent:'flex-end' }}>
          <span><span className="sw" style={{ background:'var(--bg-alt)' }} /> No deficit</span>
          <span><span className="sw" style={{ background:'color-mix(in srgb, var(--accent) 35%, var(--bg-alt))' }} /> Low</span>
          <span><span className="sw" style={{ background:'color-mix(in srgb, var(--accent) 65%, var(--bg-alt))' }} /> Mid</span>
          <span><span className="sw" style={{ background:'var(--accent)' }} /> High</span>
        </div>
      </div>

      {/* Capacity utilisation by size band */}
      <div className="section-h">
        <div className="kicker">CAPACITY</div>
        <div>
          <h2>Utilisation by company size band</h2>
          <p className="sub">Turnover consumed (awarded workload charged to revenue) versus remaining turnover per size band. The smallest firms saturate first; larger firms often keep more revenue headroom in absolute terms.</p>
        </div>
      </div>

      <div className="panel">
        <BandUtilChart stats={cur.stats} />
      </div>
    </div>
  );
}

function BandUtilChart({ stats }) {
  const fm = fmt;
  const bands = ABM.SIZE_BANDS_ORDER.map(b => ({
    band: b, ...stats.band_utilisation[b]
  })).filter(b => b.count > 0);

  return (
    <table className="dt" style={{ marginTop: 4 }}>
      <thead>
        <tr>
          <th>Size band</th>
          <th className="num">Firms</th>
          <th className="num">With spare turnover</th>
          <th className="num">Start turnover (Σ)</th>
          <th className="num">Awarded</th>
          <th>Utilisation</th>
        </tr>
      </thead>
      <tbody>
        {bands.map(b => {
          const ts = b.turnover_start ?? b.cac ?? 0;
          const util = ts > 0 ? b.used / ts : 0;
          return (
            <tr key={b.band}>
              <td className="label">{b.band}</td>
              <td className="num">{fm.fmtNum(b.count)}</td>
              <td className="num">{fm.fmtNum(b.withCap)}</td>
              <td className="num">{fm.fmtMoney(ts)}</td>
              <td className="num">{fm.fmtMoney(b.used)}</td>
              <td>
                <Chart.StackedBar
                  segments={[
                    { value: b.used, color: 'var(--ink)', label: 'Awarded' },
                    { value: Math.max(ts - b.used, 0), color: 'var(--accent)', label: 'Spare' },
                  ]}
                  height={18} format={fm.fmtMoney}
                />
                <div style={{ fontSize:10.5, color:'var(--ink-3)', marginTop:4 }}>
                  {(util*100).toFixed(1)}% utilised
                </div>
              </td>
            </tr>
          );
        })}
      </tbody>
    </table>
  );
}

/**
 * Replay the same gates as the simulation allocator for this project phase, counting
 * how many candidate firms fail each step (stuck / partial / unassigned projects only).
 *
 * Main phase: after category + region, firms fail on
 *   - CAC too small: CAC < project PAW (cannot “lead” a project of this annual scale; allocator 5c).
 *   - Turnover insufficient: current turnover would not stay above the in-house dollar charge
 *     `in_house_pct × PAW` after award (allocator 5d). This is a revenue headroom check, not RAC arithmetic.
 *
 * Sub phase: after category + region, firms fail on
 *   - CAC too small: never counted (subs have no CAC-vs-PAW gate).
 *   - RAC exhausted: no remaining annual workload budget (`RAC <= ε`), so they cannot take work (allocator 6c).
 */
function scanProjectEligibilityTrace(project, companies) {
  const seekingMain = project.main_contractor_id == null;
  const role = seekingMain ? 'main' : 'sub';
  const candidates = companies.filter(c => c.role === role);

  const tally = {
    categoryMismatch: 0,
    regionMismatch: 0,
    cacTooSmall: 0,
    turnoverOrRacBlock: 0,
    eligible: 0,
  };

  for (const c of candidates) {
    if (!compatibleX(c.category, project.category)) {
      tally.categoryMismatch++;
      continue;
    }
    if (!regionOkX(c, project.region)) {
      tally.regionMismatch++;
      continue;
    }

    if (seekingMain) {
      if (c.cac < project.paw) {
        tally.cacTooSmall++;
        continue;
      }
      const inHouseShare = c.in_house_pct * project.paw;
      if (c.turnover - inHouseShare <= ALLOCATION_EPSILON) {
        tally.turnoverOrRacBlock++;
        continue;
      }
    } else {
      if (c.rac <= ALLOCATION_EPSILON) {
        tally.turnoverOrRacBlock++;
        continue;
      }
    }

    tally.eligible++;
  }

  return { tally, total: candidates.length, seekingMain };
}

// ----- Project Drawer -----
export function ProjectDrawer({ project, run, year, onClose, onOpenCompany }) {
  const cur = run[year];
  const fm = fmt;
  if (!project) return null;
  const main = project.main_contractor_id
    ? cur.companies.find(c => c.company_id === project.main_contractor_id)
    : null;
  const subs = project.subcontractors.map(sc => ({
    ...sc, company: cur.companies.find(c => c.company_id === sc.company_id)
  }));
  const subAlloc = project.subcontractors.reduce((s, sc) => s + sc.allocated, 0);
  const unalloc = project.paw - project.main_allocated - subAlloc;

  const reasons = useMemoD(() => {
    if (project.main_contractor_id != null && project.status !== 'stuck' && project.status !== 'partial') return null;
    return scanProjectEligibilityTrace(project, cur.companies);
  }, [project, cur]);

  return (
    <>
      <div className="drawer-mask" onClick={onClose} />
      <div className="drawer">
        <div className="drawer-h">
          <div>
            <div className="eyebrow">Project · #{project.project_id}</div>
            <h2>{project.name}</h2>
            <div style={{ display:'flex', gap:6, marginTop:6 }}>
              <span className="tag">{project.category}</span>
              <span className="tag">{ABM.REGIONS.find(r=>r.name===project.region)?.name ?? project.region}</span>
              <span className={`pill ${
                project.status === 'fully_allocated' ? 'full' :
                project.status === 'partial' ? 'partial' :
                project.status === 'stuck' ? 'stuck' : 'unassigned'
              }`}>
                {project.status.replace('_',' ').toUpperCase()}
              </span>
            </div>
          </div>
          <button className="x" onClick={onClose}>×</button>
        </div>

        <div className="drawer-body">
          <dl className="dlist">
            <dt>Total value</dt>           <dd>{fm.fmtMoneyLong(project.value)}</dd>
            <dt>Duration</dt>              <dd>{project.duration} {project.duration === 1 ? 'year' : 'years'}</dd>
            <dt>Annual workload</dt>       <dd>{fm.fmtMoneyLong(project.paw)}</dd>
            <dt>Allocated this year</dt>   <dd>{fm.fmtMoneyLong(project.main_allocated + subAlloc)} ({fm.fmtPct((project.main_allocated+subAlloc)/Math.max(project.paw,1), 1)})</dd>
            <dt>Remaining</dt>             <dd>{fm.fmtMoneyLong(Math.max(unalloc, 0))}</dd>
          </dl>

          <h3 style={{ fontFamily:'var(--serif)', fontWeight:500, fontSize:14, color:'var(--ink-3)', textTransform:'uppercase', letterSpacing:'.12em', margin:'24px 0 8px' }}>
            Workload allocation
          </h3>
          <div className="alloc-bar">
            {project.main_allocated > 0 && (
              <div className="seg main" style={{ flex: project.main_allocated }}>
                Main · {fm.fmtMoney(project.main_allocated)}
              </div>
            )}
            {subAlloc > 0 && (
              <div className="seg sub" style={{ flex: subAlloc }}>
                Subs · {fm.fmtMoney(subAlloc)}
              </div>
            )}
            {unalloc > 1 && (
              <div className="seg unalloc" style={{ flex: unalloc }}>
                Unallocated · {fm.fmtMoney(unalloc)}
              </div>
            )}
            {project.main_allocated === 0 && subAlloc === 0 && unalloc === 0 && (
              <div className="seg unalloc" style={{ flex: 1 }}>—</div>
            )}
          </div>

          <h3 style={{ fontFamily:'var(--serif)', fontWeight:500, fontSize:14, color:'var(--ink-3)', textTransform:'uppercase', letterSpacing:'.12em', margin:'24px 0 8px' }}>
            Main contractor
          </h3>
          {main ? (
            <div className="panel" style={{ cursor:'pointer' }} onClick={()=>onOpenCompany(main)}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'baseline' }}>
                <div>
                  <div style={{ fontFamily:'var(--serif)', fontSize:18, fontWeight:500 }}>{main.name}</div>
                  <div style={{ fontSize:11, color:'var(--ink-3)' }}>
                    <span className="tag">{main.category}</span> · {main.size_band} · {main.reach}
                  </div>
                </div>
                <div style={{ textAlign:'right' }}>
                  <div className="tnum" style={{ fontFamily:'var(--serif)', fontSize:18 }}>{fm.fmtMoney(project.main_allocated)}</div>
                  <div style={{ fontSize:10.5, color:'var(--ink-3)' }}>{(main.in_house_pct*100).toFixed(0)}% in-house share</div>
                </div>
              </div>
            </div>
          ) : (
            <p style={{ fontFamily:'var(--serif)', fontStyle:'italic', color:'var(--ink-3)' }}>No main contractor was eligible.</p>
          )}

          <h3 style={{ fontFamily:'var(--serif)', fontWeight:500, fontSize:14, color:'var(--ink-3)', textTransform:'uppercase', letterSpacing:'.12em', margin:'24px 0 8px' }}>
            Subcontractors ({subs.length})
          </h3>
          {subs.length === 0 && (
            <p style={{ fontFamily:'var(--serif)', fontStyle:'italic', color:'var(--ink-3)' }}>None awarded.</p>
          )}
          {subs.length > 0 && (
            <table className="dt">
              <thead><tr><th>Firm</th><th>Cat</th><th>Region</th><th className="num">Allocated</th></tr></thead>
              <tbody>
                {subs.map((s,i) => (
                  <tr key={i} className="clickable" onClick={()=>onOpenCompany(s.company)}>
                    <td className="label">{s.company?.name ?? '—'}</td>
                    <td><span className="tag">{s.company?.category}</span></td>
                    <td className="dim">{ABM.REGIONS.find(r=>r.name===s.company?.region)?.name ?? '—'}</td>
                    <td className="num">{fm.fmtMoney(s.allocated)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}

          {reasons && (
            <>
              <h3 style={{ fontFamily:'var(--serif)', fontWeight:500, fontSize:14, color:'var(--ink-3)', textTransform:'uppercase', letterSpacing:'.12em', margin:'28px 0 8px' }}>
                Eligibility trace
              </h3>
              <p className="serif-italic muted" style={{ marginTop:0 }}>
                Of {fm.fmtNum(reasons.total)} candidate firms scanned:
              </p>
              <dl className="dlist">
                <dt>Category mismatch</dt> <dd>{fm.fmtNum(reasons.tally.categoryMismatch)}</dd>
                <dt>Region mismatch</dt>   <dd>{fm.fmtNum(reasons.tally.regionMismatch)}</dd>
                <dt>
                  <span className="dlist-dt-with-help">
                    CAC too small
                    <HelpTip label="Explain CAC too small">
                      <p style={{ margin: '0 0 10px' }}>
                        <strong>CAC too small</strong> is the number of candidate <strong>main</strong>{' '}
                        contractors that matched category and region but were rejected because{' '}
                        <strong>CAC &lt; PAW</strong>: their contractor annual capacity is smaller than this
                        project’s <strong>PAW</strong> (project annual workload). That is the simulation’s{' '}
                        <strong>size gate</strong> for mains (rule 5c)—the firm must be large enough to lead a
                        job of this yearly scale before turnover checks apply.
                      </p>
                      {!reasons.seekingMain && (
                        <p style={{ margin: '0 0 10px', color: 'var(--ink-2)' }}>
                          <strong>Why this stays zero here:</strong> this trace is for the{' '}
                          <strong>subcontractor</strong> pass, which does not use a CAC-vs-PAW gate (only
                          category, region, and positive RAC). The counter is not incremented for subs.
                        </p>
                      )}
                      {reasons.seekingMain && reasons.tally.cacTooSmall === 0 && (
                        <p style={{ margin: 0, color: 'var(--ink-2)' }}>
                          <strong>When this is zero:</strong> among mains who matched category and region, none
                          failed <em>only</em> because CAC was below PAW—either they failed on a different rule,
                          or at least one main cleared every gate.
                        </p>
                      )}
                    </HelpTip>
                  </span>
                </dt>
                <dd>{fm.fmtNum(reasons.tally.cacTooSmall)}</dd>
                <dt>
                  <span className="dlist-dt-with-help">
                    {reasons.seekingMain ? 'Turnover insufficient' : 'RAC exhausted'}
                    <HelpTip label={reasons.seekingMain ? 'Explain turnover insufficient' : 'Explain RAC exhausted'}>
                      {reasons.seekingMain ? (
                        <>
                          <p style={{ margin: '0 0 10px' }}>
                            <strong>Turnover insufficient</strong> is the number of candidate{' '}
                            <strong>main</strong> contractors that matched category and region, passed{' '}
                            <strong>CAC ≥ PAW</strong>, but were rejected because their{' '}
                            <strong>remaining turnover</strong> could not absorb the in-house dollar charge for
                            this award: <strong>turnover − in_house_pct × PAW</strong> would not stay positive
                            (rule 5d). This is a <strong>revenue headroom</strong> check, not a RAC arithmetic
                            step.
                          </p>
                          {reasons.tally.turnoverOrRacBlock === 0 && (
                            <p style={{ margin: 0, color: 'var(--ink-2)' }}>
                              <strong>When this is zero:</strong> no main who reached this step failed on
                              turnover alone—either earlier gates culled everyone, or some mains still had enough
                              revenue after the in-house share.
                            </p>
                          )}
                        </>
                      ) : (
                        <>
                          <p style={{ margin: '0 0 10px' }}>
                            <strong>RAC exhausted</strong> is the number of candidate{' '}
                            <strong>subcontractors</strong> that matched category and region but had{' '}
                            <strong>no annual workload budget left</strong>: remaining annual capacity (RAC) is
                            at or below zero (within a tiny numerical tolerance). In this model, subcontractor
                            RAC tracks the same pool as <strong>remaining turnover</strong> (rule 6c).
                          </p>
                          {reasons.tally.turnoverOrRacBlock === 0 && (
                            <p style={{ margin: 0, color: 'var(--ink-2)' }}>
                              <strong>When this is zero:</strong> every sub that matched category and region
                              still had positive RAC—running out of RAC was not the reason none could take work
                              (look at category, region, or other failures instead).
                            </p>
                          )}
                        </>
                      )}
                    </HelpTip>
                  </span>
                </dt>
                <dd>{fm.fmtNum(reasons.tally.turnoverOrRacBlock)}</dd>
                <dt>Eligible</dt>          <dd><b>{fm.fmtNum(reasons.tally.eligible)}</b></dd>
              </dl>
            </>
          )}
        </div>
      </div>
    </>
  );
}

function compatibleX(companyCategoryName, projectCat) {
  const c = ABM.COMPANY_CATEGORIES.find(x => x.name === companyCategoryName);
  return !!c && c.covers.includes(projectCat);
}
function regionOkX(company, projectRegion) {
  if (company.reach === 'National') return true;
  const cR = ABM.REGIONS.find(r => r.name === company.region);
  const pR = ABM.REGIONS.find(r => r.name === projectRegion);
  if (!cR || !pR) return false;
  if (company.reach === 'Multi-region') return cR.island === pR.island;
  return cR.name === pR.name;
}

// ----- Company Drawer -----
export function CompanyDrawer({ company, run, year, onClose, onOpenProject }) {
  const cur = run[year];
  const fm = fmt;
  if (!company) return null;

  const awardedMain = company.awarded_main.map(a => ({
    ...a, project: cur.projects.find(p => p.project_id === a.project_id), as: 'Main'
  }));
  const awardedSub = company.awarded_sub.map(a => ({
    ...a, project: cur.projects.find(p => p.project_id === a.project_id), as: 'Sub'
  }));
  const all = [...awardedMain, ...awardedSub].sort((a,b)=>b.allocated - a.allocated);

  const initialT = company.initial_turnover ?? company.turnover;
  const remainingT = company.turnover;
  const usedRev = initialT - remainingT;

  return (
    <>
      <div className="drawer-mask" onClick={onClose} />
      <div className="drawer">
        <div className="drawer-h">
          <div>
            <div className="eyebrow">Company · #{company.company_id}</div>
            <h2>{company.name}</h2>
            <div style={{ display:'flex', gap:6, marginTop:6 }}>
              <span className="tag">{company.category}</span>
              <span className="tag">{ABM.REGIONS.find(r=>r.name===company.region)?.name ?? company.region}</span>
              <span className="tag">{company.reach}</span>
              <span className={`pill ${company.role === 'main' ? 'partial' : 'full'}`}>
                {company.role === 'main' ? 'MAIN' : 'SUB'}
              </span>
            </div>
          </div>
          <button className="x" onClick={onClose}>×</button>
        </div>

        <div className="drawer-body">
          <dl className="dlist">
            <dt>Turnover (start of year)</dt> <dd>{fm.fmtMoneyLong(initialT)}</dd>
            <dt>Turnover (after allocation)</dt> <dd><b>{fm.fmtMoneyLong(remainingT)}</b></dd>
            <dt>Size band</dt>                <dd>{company.size_band}</dd>
            <dt>In-house share (start)</dt>   <dd>{(company.in_house_pct*100).toFixed(0)}%</dd>
            <dt>Revenue utilised</dt>        <dd>{fm.fmtMoneyLong(Math.max(usedRev, 0))}</dd>
            <dt>CAC (simulation)</dt>         <dd>{fm.fmtMoneyLong(company.cac)} <span style={{ color:'var(--ink-3)', fontSize:11 }}>main size gate only</span></dd>
            <dt>RAC (simulation)</dt>          <dd>{fm.fmtMoneyLong(company.rac)}</dd>
          </dl>

          <h3 style={{ fontFamily:'var(--serif)', fontWeight:500, fontSize:14, color:'var(--ink-3)', textTransform:'uppercase', letterSpacing:'.12em', margin:'24px 0 8px' }}>
            Turnover utilisation
          </h3>
          <Chart.StackedBar
            segments={[
              { value: Math.max(usedRev, 0), color: 'var(--ink)', label: 'Utilised' },
              { value: Math.max(remainingT, 0), color: 'var(--accent)', label: 'Remaining' },
            ]}
            height={28} format={fm.fmtMoney}
          />
          <div style={{ display:'flex', justifyContent:'space-between', marginTop:6, fontSize:11, color:'var(--ink-3)', fontVariantNumeric:'tabular-nums' }}>
            <span>{(Math.max(usedRev,0) / Math.max(initialT,1) * 100).toFixed(1)}% utilised</span>
            <span>{fm.fmtMoney(remainingT)} remaining</span>
          </div>

          <h3 style={{ fontFamily:'var(--serif)', fontWeight:500, fontSize:14, color:'var(--ink-3)', textTransform:'uppercase', letterSpacing:'.12em', margin:'24px 0 8px' }}>
            Awarded projects ({all.length})
          </h3>
          {all.length === 0 && (
            <p style={{ fontFamily:'var(--serif)', fontStyle:'italic', color:'var(--ink-3)' }}>No projects awarded this year.</p>
          )}
          {all.length > 0 && (
            <table className="dt">
              <thead><tr><th>Project</th><th>Cat</th><th>Region</th><th>Role</th><th className="num">Allocated</th></tr></thead>
              <tbody>
                {all.map((a,i) => (
                  <tr key={i} className="clickable" onClick={()=>a.project && onOpenProject(a.project)}>
                    <td className="label">{a.project?.name ?? '—'}<div style={{ fontSize:10, color:'var(--ink-3)' }}>#{a.project_id}</div></td>
                    <td><span className="tag">{a.project?.category}</span></td>
                    <td className="dim">{ABM.REGIONS.find(r=>r.name===a.project?.region)?.name ?? '—'}</td>
                    <td><span className={`pill ${a.as === 'Main' ? 'partial' : 'full'}`}>{a.as}</span></td>
                    <td className="num">{fm.fmtMoney(a.allocated)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </>
  );
}

